// === EMBEDDED BASE64 IMAGES (Hostinger-friendly, no external file deps) ===
window.IMG = {
  logo:    "data:image/png;base64,",
  ceg:     "data:image/jpeg;base64,",
  qrweb:   "data:image/png;base64,",
  qrwa:    "data:image/jpeg;base64,",
  poster:  "data:image/jpeg;base64,",
};

// === HAMBURGER + SMOOTH ANCHOR SCROLL ===
// Bulletproofed: direct per-link listeners + document delegator + native href fallback.
// Diagnostics: emits console.log on every click so you can verify in DevTools that
// the handler is firing. If something blocks our smooth scroll, the native href
// still works because we only preventDefault AFTER confirming the scroll succeeded.
const hb = document.getElementById('hamburger');
const nl = document.getElementById('navLinks');
hb && hb.addEventListener('click', () => nl.classList.toggle('open'));

// Explicit anchor handling for every <a href="#..."> in the page (nav + hero CTAs + inline)
function scrollToAnchor(href, opts) {
  if (!href || !href.startsWith('#') || href.length < 2) return false;

  // === Smart target routing ===
  // The gate (#student-gate) and the predictor (#predictor) are mutually-exclusive
  // in student mode (one is hidden depending on whether the form was submitted).
  // If a link points to a currently-hidden one, route to the visible counterpart.
  if (href === '#student-gate' || href === '#predictor') {
    const gate = document.getElementById('student-gate');
    const pred = document.getElementById('predictor');
    const gateVisible = gate && getComputedStyle(gate).display !== 'none';
    const predVisible = pred && getComputedStyle(pred).display !== 'none';
    if (href === '#student-gate' && !gateVisible && predVisible) href = '#predictor';
    else if (href === '#predictor' && !predVisible && gateVisible) href = '#student-gate';
  }

  let target = document.querySelector(href);
  if (!target) return false;

  // Walk up if hidden — find the first visible ancestor section
  while (target && getComputedStyle(target).display === 'none') {
    target = target.parentElement;
    if (!target || target === document.body) return false;
  }

  // Compute the destination scroll position
  const header = document.querySelector('header');
  const offset = header ? header.getBoundingClientRect().height + 12 : 80;
  const top = target.getBoundingClientRect().top + window.pageYOffset - offset;
  const startY = window.pageYOffset;

  // Method 1: window.scrollTo with smooth behavior (works in all browsers from 2017+)
  try {
    window.scrollTo({ top, behavior: (opts && opts.behavior) || 'smooth' });
  } catch (e) {
    try { window.scrollTo(0, top); } catch (e2) { /* swallow */ }
  }

  // Method 2 (verification): after 400ms, check if scroll moved at all.
  // If not (browser ignored our request for some reason), force instant scroll.
  setTimeout(() => {
    if (Math.abs(window.pageYOffset - startY) < 5 && Math.abs(window.pageYOffset - top) > 50) {
      // Smooth scroll never started — fall back to instant
      try { window.scrollTo(0, top); } catch (e) { /* last resort */ }
      try { target.scrollIntoView({ block: 'start' }); } catch (e) { /* swallow */ }
    }
  }, 400);

  return true;
}

// === Direct per-link click handlers (primary defense) ===
// We attach handlers to each anchor link individually. This is more reliable than
// document-level delegation because no parent element can stop the click propagation
// before it reaches us.
function bindOneAnchorLink(a) {
  if (!a || a.dataset.eaNavBound === '1') return; // already bound
  if (a.hasAttribute('data-no-scroll')) return;
  const href = a.getAttribute('href');
  if (!href || !href.startsWith('#') || href.length < 2) return;
  a.dataset.eaNavBound = '1';
  a.addEventListener('click', function(ev) {
    try { console.log('[EduAakashaa nav] click:', this.getAttribute('href')); } catch(_) {}
    const linkHref = this.getAttribute('href');
    if (scrollToAnchor(linkHref)) {
      ev.preventDefault();
      nl && nl.classList.remove('open');
      try { history.replaceState(null, '', linkHref); } catch(_) {}
    }
    // If scrollToAnchor returns false, do NOT preventDefault — let the browser
    // handle the anchor natively as a fallback.
  });
}

function bindAllAnchorLinks() {
  document.querySelectorAll('a[href^="#"]').forEach(bindOneAnchorLink);
}

// Bind on DOM ready, on window load, AND immediately (in case DOM is already ready).
// Multiple binding attempts are safe because of the data-eaNavBound flag.
bindAllAnchorLinks();
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', bindAllAnchorLinks);
}
window.addEventListener('load', bindAllAnchorLinks);
// Re-bind after 1 second too, in case any links were added by other scripts late.
setTimeout(bindAllAnchorLinks, 1000);

// === Document-level delegator (secondary safety net) ===
// In case any link is added dynamically and missed by the per-link binder.
document.addEventListener('click', (e) => {
  const a = e.target.closest('a[href^="#"]');
  if (!a) return;
  if (a.dataset.eaNavBound === '1') return; // already handled by per-link listener
  const href = a.getAttribute('href');
  if (!href || href === '#' || href.length < 2) return;
  if (a.hasAttribute('data-no-scroll')) return;
  if (scrollToAnchor(href)) {
    e.preventDefault();
    nl && nl.classList.remove('open');
    try { history.replaceState(null, '', href); } catch(_) {}
  }
});

// Scroll reveal
const io = new IntersectionObserver((entries)=>{
  entries.forEach(e=>{ if(e.isIntersecting){ e.target.classList.add('visible'); io.unobserve(e.target); } });
},{threshold:.12});
document.querySelectorAll('.reveal').forEach(el=>io.observe(el));

// Document checklist
const docCards = document.querySelectorAll('.doc-card');
const docCountN = document.getElementById('docCountN');
function updateDocCount(){
  const n = document.querySelectorAll('.doc-card.checked').length;
  docCountN.textContent = n;
}
docCards.forEach(c=>{
  c.addEventListener('click',()=>{
    c.classList.toggle('checked');
    updateDocCount();
  });
  c.addEventListener('keydown',(e)=>{
    if(e.key==='Enter'||e.key===' '){ e.preventDefault(); c.click(); }
  });
  c.setAttribute('tabindex','0');
  c.setAttribute('role','checkbox');
  c.setAttribute('aria-checked','false');
});

// FAQ accordion
document.querySelectorAll('.faq-item').forEach(item=>{
  item.addEventListener('click',(e)=>{
    if(e.target.closest('.faq-a')) return;
    document.querySelectorAll('.faq-item').forEach(i=>{ if(i!==item) i.classList.remove('open'); });
    item.classList.toggle('open');
  });
});

// Zone bar animation on scroll
const zoneBars = document.querySelectorAll('.zone-bar-fill');
const zoneBarObs = new IntersectionObserver((entries)=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      const w = e.target.style.width;
      e.target.style.width = '0%';
      setTimeout(()=>{ e.target.style.width = w; }, 80);
      zoneBarObs.unobserve(e.target);
    }
  });
},{threshold:.3});
zoneBars.forEach(b=>zoneBarObs.observe(b));

// Animate reservation bars on reveal
const resBars = document.querySelectorAll('.reserve-bar .fill');
const resObserver = new IntersectionObserver((entries)=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      const w = e.target.style.width;
      e.target.style.width = '0%';
      setTimeout(()=>{ e.target.style.width = w; }, 100);
      resObserver.unobserve(e.target);
    }
  });
},{threshold:.3});
resBars.forEach(b=>resObserver.observe(b));

