// ============================================================
// RENDER COLLEGES TABLE
// ============================================================
function naacClass(grade){
  if(grade==='A++') return 'naac-aplusplus';
  if(grade==='A+') return 'naac-aplus';
  if(grade==='A') return 'naac-a';
  return 'naac-na';
}
function typeClass(t){ return 'type-'+t; }

function renderColleges(filter='all', search=''){
  const body = document.getElementById('collegesBody');
  if(!body) return;
  const sNorm = search.trim().toLowerCase();
  const rows = COLLEGES.filter(c=>{
    // filter
    if(filter==='tnea' && c.admitClass!=='tnea') return false;
    if(filter==='govt' && !(c.typeFamily==='govt')) return false;
    if(filter==='private' && c.typeFamily!=='private') return false;
    if(filter==='deemed' && c.typeFamily!=='deemed') return false;
    // search
    if(sNorm){
      const hay = (c.name+' '+c.short+' '+c.city+' '+c.typeLabel).toLowerCase();
      if(!hay.includes(sNorm)) return false;
    }
    return true;
  }).map(c=>`
    <tr data-type="${c.typeFamily}" data-admit="${c.admitClass}">
      <td class="col-rank"><span class="rank-badge">${c.rank}</span></td>
      <td>
        <div class="col-name-cell">
          <div class="col-name-text">
            <div class="col-name-primary">${c.name}</div>
            <div class="col-name-secondary">${c.short}</div>
          </div>
        </div>
      </td>
      <td class="col-loc">${c.city}</td>
      <td><span class="naac-pill ${naacClass(c.naac)}">${c.naac}</span></td>
      <td class="col-est">${c.est}</td>
      <td><span class="type-pill ${typeClass(c.type)}">${c.typeLabel}</span></td>
      <td class="col-cutoff">${c.cutoff}</td>
      <td class="col-place">${c.highest}</td>
      <td class="col-median">${c.median}</td>
      <td><span class="col-admit-cell ${c.admitClass}">${c.admission}</span></td>
    </tr>
  `).join('');
  body.innerHTML = rows || `<tr><td colspan="10" style="text-align:center;padding:40px;color:var(--muted)">No colleges match your search. Try a different keyword.</td></tr>`;
}
renderColleges();

// Search & filter wiring
const colleges_search = document.getElementById('collegeSearch');
let activeFilter = 'all';
if(colleges_search){
  colleges_search.addEventListener('input', e=> renderColleges(activeFilter, e.target.value));
}
document.querySelectorAll('.col-filter').forEach(btn=>{
  btn.addEventListener('click',()=>{
    document.querySelectorAll('.col-filter').forEach(b=> b.classList.remove('active'));
    btn.classList.add('active');
    activeFilter = btn.dataset.filter;
    renderColleges(activeFilter, colleges_search?.value || '');
  });
});

