function getNirf(collegeIdx){ return NIRF_RANKS[collegeIdx] || null; }
// Does a record pass the user's NIRF filter?
function passesNirfFilter(collegeIdx, filterValue){
  if(filterValue === 'all') return true;
  const n = NIRF_RANKS[collegeIdx];
  if(filterValue === 'unranked') return !n;
  if(!n) return false;
  if(filterValue === 'ranked')  return true;
  if(filterValue === 'top50')   return n.rank <= 50;
  if(filterValue === 'top100')  return n.rank <= 100;
  if(filterValue === 'top200')  return n.rank <= 200;
  if(filterValue === 'top300')  return n.rank <= 300;
  return true;
}
// Visual badge HTML
function nirfBadge(collegeIdx){
  const n = NIRF_RANKS[collegeIdx];
  if(!n) return '';
  return `<span class="nirf-badge nirf-${n.band}" title="NIRF 2024 Engineering rank ${n.display} — verify at nirfindia.org">#${n.display}</span>`;
}

// Populate district dropdown from data
function populateDistrictDropdown(){
  const sel = document.getElementById('dFilterDistrict');
  if(!sel) return;
  const districts = Array.from(new Set(TNEA_DATA.colleges.map(c=>c.d))).sort();
  for(const d of districts){
    const opt = document.createElement('option');
    opt.value = d; opt.textContent = d.charAt(0)+d.slice(1).toLowerCase();
    sel.appendChild(opt);
  }
}

// Populate branch dropdown — group all 106 branches by course-group with optgroups
function populateBranchDropdown(){
  const sel = document.getElementById('dFilterBranch');
  if(!sel) return;
  // Build code → name lookup from data, then group by COURSE_GROUP_MAP
  const allBranches = TNEA_DATA.branches.map(b => ({code: b.c, name: b.n}));
  // Sort branches alphabetically within each group
  const groupOrder = [
    {key:'computing',  label:'Computing — CS · AI · IT · Cyber'},
    {key:'electronics',label:'Electronics — ECE · EEE · E&I · VLSI'},
    {key:'core',       label:'Core — Mech · Aero · Auto · Robotics'},
    {key:'civil',      label:'Civil & Structural — Civil · Arch · Env'},
    {key:'biochem',    label:'Bio & Chemical — Biotech · Biomed · Chem · Food'},
    {key:'other',      label:'Other / Specialised — Textile · Leather'},
  ];
  // Track branches assigned to a group; leftovers go to "Uncategorised"
  const assigned = new Set();
  for(const g of groupOrder){
    const branchesInGroup = allBranches.filter(b => COURSE_GROUP_MAP[g.key].includes(b.code));
    if(branchesInGroup.length === 0) continue;
    branchesInGroup.sort((a,b) => a.code.localeCompare(b.code));
    const optgroup = document.createElement('optgroup');
    optgroup.label = g.label;
    for(const b of branchesInGroup){
      const opt = document.createElement('option');
      opt.value = b.code;
      const niceName = b.name.length > 50 ? b.name.substring(0,50)+'…' : b.name;
      opt.textContent = `${b.code} · ${niceName}`;
      optgroup.appendChild(opt);
      assigned.add(b.code);
    }
    sel.appendChild(optgroup);
  }
  // Anything not in a group
  const leftovers = allBranches.filter(b => !assigned.has(b.code));
  if(leftovers.length){
    const optgroup = document.createElement('optgroup');
    optgroup.label = 'Other branches';
    leftovers.sort((a,b) => a.code.localeCompare(b.code));
    for(const b of leftovers){
      const opt = document.createElement('option');
      opt.value = b.code;
      opt.textContent = `${b.code} · ${b.name.substring(0,50)}`;
      optgroup.appendChild(opt);
    }
    sel.appendChild(optgroup);
  }
}

// Returns true if a record passes the active filters
function passesFilters(record){
  const college = TNEA_DATA.colleges[record[0]];
  const branch = TNEA_DATA.branches[record[1]];
  const f = DASH.filters;
  // Zone
  if(f.zone !== 'all'){
    const dists = ZONE_DISTRICTS[f.zone] || [];
    if(!dists.includes(college.d)) return false;
  }
  // District
  if(f.district !== 'all' && college.d !== f.district) return false;
  // Type
  if(f.type !== 'all' && college.t !== f.type) return false;
  // Tier preset
  if(f.tier !== 'all'){
    const allowed = TIER_GROUPS_FILTER[f.tier];
    if(allowed && !allowed.includes(college.t)) return false;
  }
  // Course group
  if(f.courseGroup !== 'all'){
    const branchCodesInGroup = COURSE_GROUP_MAP[f.courseGroup] || [];
    if(!branchCodesInGroup.includes(branch.c)) return false;
  }
  // Specific branch
  if(f.branch !== 'all' && branch.c !== f.branch) return false;
  // NIRF
  if(!passesNirfFilter(record[0], f.nirf)) return false;
  // EA Rank tier
  if(f.eaTier && f.eaTier !== 'all'){
    const ea = EA_RANK[record[0]];
    if(ea == null) return false; // Unranked colleges excluded when an EA tier is selected
    const tierMax = { top30:30, top50:50, top100:100, top200:200, top300:300, top400:400, top600:600 }[f.eaTier] || 9999;
    if(ea > tierMax) return false;
  }
  return true;
}

function activeFilterCount(){
  const f = DASH.filters;
  let n = 0;
  if(f.zone !== 'all') n++;
  if(f.district !== 'all') n++;
  if(f.type !== 'all') n++;
  if(f.tier !== 'all') n++;
  if(f.courseGroup !== 'all') n++;
  if(f.branch !== 'all') n++;
  if(f.nirf !== 'all') n++;
  if(f.eaTier && f.eaTier !== 'all') n++;
  return n;
}

function updateFilterCountBadge(){
  const el = document.getElementById('dFiltersCount');
  if(!el) return;
  const n = activeFilterCount();
  el.textContent = n > 0 ? `${n} active` : '';
}

// === EA-RANK-DRIVEN DREAM/REACH/SAFE PICKS ===
// Algorithm:
// 1. For each reachable record (cutoff <= user's), find the best (lowest EA-rank) college-branch
//    that fits the user's filters. Dedup by college so we surface different colleges.
// 2. Bucket by headroom band:
//      DREAM: -5 ≤ headroom < +3   (slight stretch — but EA top colleges may convert)
//      REACH: +3 ≤ headroom < +8   (comfortable margin)
//      SAFE:  headroom ≥ +8        (almost-certain allotment)
// 3. Within each bucket, sort by EA rank ascending (best college first), take top 10.
// 4. Render with NIRF + NAAC badges flagged on each card.
function renderTierPicks(){
  // Get all wrap elements
  const wraps = {
    dream: document.getElementById('dDreamWrap'),
    reach: document.getElementById('dReachWrap'),
    safe : document.getElementById('dSafeWrap'),
  };
  if(!wraps.dream || !wraps.reach || !wraps.safe) return;

  const ci = COMM_IDX[DASH.community];

  // For DREAM tier we allow a slight under-cutoff (down to -5) because EA top colleges
  // sometimes convert seats in later rounds even when the user is just below the closing cutoff.
  // For REACH and SAFE we require strictly reachable (cutoff <= user's).
  const candidates = TNEA_DATA.records
    .filter(r => r[ci] != null && (DASH.cutoff - r[ci]) >= -5 && passesFilters(r))
    .map(r => {
      const college = TNEA_DATA.colleges[r[0]];
      const branch = TNEA_DATA.branches[r[1]];
      const headroom = DASH.cutoff - r[ci];
      // EA rank: lower is better. Colleges without EA rank get a high penalty value (999) so
      // they fall to the bottom — we don't want unranked colleges in the top 10 lists.
      const ea = EA_RANK[r[0]] || 999;
      return { r, college, branch, cutoff: r[ci], headroom, ea };
    });

  // Helper: dedup by college (keep best EA-ranked branch per college), then sort by EA
  function dedupAndSort(arr){
    const seen = new Map();
    for(const c of arr){
      const existing = seen.get(c.r[0]);
      if(!existing || c.ea < existing.ea){
        seen.set(c.r[0], c);
      }
    }
    return Array.from(seen.values()).sort((a, b) => a.ea - b.ea);
  }

  // Bucket
  const dreamCands = dedupAndSort(candidates.filter(c => c.headroom >= -5 && c.headroom < 3));
  const reachCands = dedupAndSort(candidates.filter(c => c.headroom >= 3  && c.headroom < 8));
  const safeCands  = dedupAndSort(candidates.filter(c => c.headroom >= 8));

  // For DREAM specifically, also de-duplicate against REACH+SAFE (so the same college doesn't
  // appear in two tiers). We give higher priority to DREAM > REACH > SAFE.
  const dream = dreamCands.slice(0, 10);
  const usedDream = new Set(dream.map(c => c.r[0]));
  const reach = reachCands.filter(c => !usedDream.has(c.r[0])).slice(0, 10);
  const usedReach = new Set([...usedDream, ...reach.map(c => c.r[0])]);
  const safe = safeCands.filter(c => !usedReach.has(c.r[0])).slice(0, 10);

  renderTierGrid(wraps.dream, dream, 'dream');
  renderTierGrid(wraps.reach, reach, 'reach');
  renderTierGrid(wraps.safe,  safe,  'safe');
}

function renderTierGrid(wrap, cards, tier){
  if(cards.length === 0){
    let msg;
    if(tier === 'dream')      msg = "No dream colleges in reach for your current cutoff and filters. Either raise your cutoff target or relax filters (e.g. zone, NIRF).";
    else if(tier === 'reach') msg = "No reach colleges fit the +3 to +8 headroom band right now. Try widening filters or check the dream / safe tiers.";
    else                       msg = "No safe colleges with +8 or more headroom for your filters. Either lower the cutoff target or relax course/zone filters.";
    wrap.innerHTML = `<div class="dash-safe-empty">${msg}</div>`;
    return;
  }
  wrap.innerHTML = cards.map((c, i) => {
    const collegeName = c.college.n.length > 60 ? c.college.n.substring(0,60)+'…' : c.college.n;
    const branchName  = c.branch.n.length > 38 ? c.branch.n.substring(0,38)+'…' : c.branch.n;
    const eaPillCls   = c.ea <= 10 ? 'ea-top10' : c.ea <= 50 ? 'ea-top50' : c.ea <= 100 ? 'ea-top100' : '';
    const eaLabel     = c.ea < 999 ? `EA #${c.ea}` : 'Unranked';
    const nirf        = nirfBadge(c.r[0]);
    const naac        = naacBadge(c.r[0]);
    const headSign    = c.headroom >= 0 ? '+' : '';
    const headCls     = c.headroom >= 8 ? 'headroom-strong' : c.headroom >= 3 ? '' : c.headroom >= 0 ? 'headroom-tight' : 'headroom-stretch';
    return `<div class="dash-ea-card tier-${tier}">
      <div class="dash-ea-toprow">
        <span class="dash-ea-rank-pill ${eaPillCls}">${eaLabel}</span>
        <span class="dash-ea-position">#${i+1}</span>
      </div>
      <div class="dash-ea-college" title="${c.college.n}">${collegeName}</div>
      <div class="dash-ea-flags">${nirf}${naac}</div>
      <div class="dash-ea-meta">
        <span><strong>${c.branch.c}</strong> · ${branchName}</span>
        <span>${c.college.d} · ${c.college.t}</span>
      </div>
      <div class="dash-ea-stats">
        <div class="dash-ea-stat"><span class="dash-ea-stat-label">2025 Cutoff</span><span class="dash-ea-stat-val">${c.cutoff}</span></div>
        <div class="dash-ea-stat"><span class="dash-ea-stat-label">Headroom</span><span class="dash-ea-stat-val ${headCls}">${headSign}${c.headroom.toFixed(1)}</span></div>
      </div>
    </div>`;
  }).join('');
}

// Backwards-compat alias — the dashboard refresh used to call renderSafePicks
function renderSafePicks(){ return renderTierPicks(); }

// NAAC grade badge — displays the verified accreditation grade where known
function naacBadge(collegeIdx){
  const g = NAAC_GRADES[collegeIdx];
  if(!g) return '';
  const cls = g === 'A++' ? 'naac-aplusplus' : g === 'A+' ? 'naac-aplus' : g === 'A' ? 'naac-a' : g === 'B++' ? 'naac-bplusplus' : g === 'B+' ? 'naac-bplus' : 'naac-b';
  return `<span class="naac-badge ${cls}" title="NAAC accreditation grade ${g} — verified from official sources">${g}</span>`;
}

// Patch renderPredictor to apply filters + user-chosen sort
const _origRenderPredictor = renderPredictor;
renderPredictor = function(){
  const tbody = document.getElementById('dPredictorBody');
  const countEl = document.getElementById('dPredCount');
  if(!tbody) return;
  const ci = COMM_IDX[DASH.community];

  let records = TNEA_DATA.records.filter(r=>{
    if(r[ci]==null) return false;
    if(DASH.predBranch !== 'ALL' && TNEA_DATA.branches[r[1]].c !== DASH.predBranch) return false;
    if(!passesFilters(r)) return false;
    return true;
  });
  let reachable = records.filter(r => r[ci] <= DASH.cutoff + 2);

  // === Apply user-selected sort ===
  // NAAC ordering: A++ = 6, A+ = 5, A = 4, B++ = 3, B+ = 2, B = 1, others = 0
  const naacScore = (g) => ({'A++':6,'A+':5,'A':4,'B++':3,'B+':2,'B':1}[g] || 0);
  const sortKey = (DASH.predSort || 'cutoff_desc');
  reachable.sort((a, b) => {
    const colA = TNEA_DATA.colleges[a[0]], colB = TNEA_DATA.colleges[b[0]];
    const brA  = TNEA_DATA.branches[a[1]], brB  = TNEA_DATA.branches[b[1]];
    const eaA  = EA_RANK[a[0]] != null ? EA_RANK[a[0]] : 9999;
    const eaB  = EA_RANK[b[0]] != null ? EA_RANK[b[0]] : 9999;
    const niA  = (NIRF_RANKS[a[0]] && NIRF_RANKS[a[0]].rank != null) ? NIRF_RANKS[a[0]].rank : 9999;
    const niB  = (NIRF_RANKS[b[0]] && NIRF_RANKS[b[0]].rank != null) ? NIRF_RANKS[b[0]].rank : 9999;
    const naA  = naacScore(NAAC_GRADES[a[0]]);
    const naB  = naacScore(NAAC_GRADES[b[0]]);
    const cuA  = a[ci], cuB  = b[ci];
    const hrA  = DASH.cutoff - cuA, hrB = DASH.cutoff - cuB;
    switch (sortKey) {
      case 'cutoff_asc':    return cuA - cuB;
      case 'cutoff_desc':   return cuB - cuA;
      case 'headroom_asc':  return hrA - hrB;
      case 'headroom_desc': return hrB - hrA;
      case 'ea_asc':        return eaA - eaB;
      case 'ea_desc':       return eaB - eaA;
      case 'nirf_asc':      return niA - niB;
      case 'naac_asc':      return naB - naA; // higher score → first
      case 'college_asc':   return colA.n.localeCompare(colB.n);
      case 'branch_asc':    return brA.n.localeCompare(brB.n);
      default:              return cuB - cuA;
    }
  });

  const top = reachable.slice(0, 30);
  countEl.innerHTML = `<strong>${reachable.length}</strong> reachable college-branch combinations · showing top ${top.length}`;
  if(top.length === 0){
    tbody.innerHTML = `<tr><td colspan="10" class="dash-pred-empty">No reachable colleges match your cutoff (${DASH.cutoff}) and current filters. Try widening the filter or clearing zone/district/type filters.</td></tr>`;
    return;
  }
  tbody.innerHTML = top.map((r, i)=>{
    const college = TNEA_DATA.colleges[r[0]];
    const branch = TNEA_DATA.branches[r[1]];
    const cutoff = r[ci];
    const headroom = (DASH.cutoff - cutoff).toFixed(1);
    const fit = fitClass(DASH.cutoff, cutoff);
    const fitLabel = fit==='strong'?'STRONG':fit==='likely'?'LIKELY':fit==='stretch'?'STRETCH':'—';
    const rankClass = i < 3 ? 'dash-pred-rank dash-pred-rank-top' : 'dash-pred-rank';
    const headSign = headroom > 0 ? '+' : '';
    const headColor = headroom >= 3 ? '#0E6B40' : headroom >= 0 ? '#9A3D00' : '#C23A3A';
    const ea = EA_RANK[r[0]];
    const eaCell = ea != null ? `<span style="font-weight:700;color:${ea<=30?'#0E6B40':ea<=100?'#0E3A8A':'var(--ink)'}">${ea}</span>` : '<span style="color:var(--muted)">—</span>';
    const nirfObj = NIRF_RANKS[r[0]];
    const nirfRank = nirfObj ? nirfObj.rank : null;
    const nirfDisp = nirfObj ? nirfObj.display : null;
    const nirfCell = nirfDisp != null ? `<span style="font-weight:700;color:${nirfRank<=50?'#0E6B40':nirfRank<=200?'#0E3A8A':'var(--ink)'}">${nirfDisp}</span>` : '<span style="color:var(--muted)">—</span>';
    const naac = NAAC_GRADES[r[0]];
    const naacCell = naac ? `<span style="background:${naac==='A++'?'#0E6B40':naac==='A+'?'#1F8B5C':naac==='A'?'#0E3A8A':'#9A6B00'};color:#fff;padding:1px 6px;border-radius:4px;font-family:'JetBrains Mono',monospace;font-size:9.5px;font-weight:700">${naac}</span>` : '<span style="color:var(--muted)">—</span>';
    return `<tr>
      <td><span class="${rankClass}">${i+1}</span></td>
      <td>${college.n} <span style="display:block;font-family:'JetBrains Mono',monospace;font-size:10px;color:var(--muted);margin-top:2px">${college.d}</span></td>
      <td><span style="font-weight:600">${branch.c}</span> <span style="display:block;font-family:'JetBrains Mono',monospace;font-size:10px;color:var(--muted);margin-top:2px">${branch.n.substring(0,38)}${branch.n.length>38?'…':''}</span></td>
      <td class="num">${eaCell}</td>
      <td class="num">${nirfCell}</td>
      <td class="num">${naacCell}</td>
      <td class="num"><strong>${cutoff}</strong></td>
      <td class="num" style="color:${headColor};font-weight:700">${headSign}${headroom}</td>
      <td><span style="font-family:'JetBrains Mono',monospace;font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.06em">${college.t}</span></td>
      <td><span class="dash-fit-pill dash-fit-${fit}">${fitLabel}</span></td>
    </tr>`;
  }).join('');
};

