// ============================================================
// === SESSION + MODE + GATE + EXPERT WORKSPACE ===============
// ============================================================
//
// Configurable endpoints — set these to your deployed Apps Script URL.
// See google_sheets_setup.md for full deployment instructions.
const APPS_SCRIPT_URL = ''; // e.g. 'https://script.google.com/macros/s/AKfyc.../exec'
const EXPERT_PIN = 'edu2026'; // Change this to your real PIN. (Stored client-side; for higher security, validate server-side via Apps Script.)
const SESSION_KEY = 'eduaakashaa_student_session_v2';
const EXPERT_KEY  = 'eduaakashaa_expert_authed';
const MODE_KEY    = 'eduaakashaa_mode';

// === Mode state ===
const MODE = { current: 'student', expertAuthed: false, activeRequest: null, allRequests: [] };

function setMode(m) {
  MODE.current = m;
  document.body.classList.toggle('mode-student', m === 'student');
  document.body.classList.toggle('mode-expert',  m === 'expert');
  document.querySelectorAll('.mode-btn').forEach(b => {
    const isActive = b.dataset.mode === m;
    b.classList.toggle('mode-btn-active', isActive);
    b.setAttribute('aria-selected', String(isActive));
  });
  try { localStorage.setItem(MODE_KEY, m); } catch(e){}
  refreshModeUI();
}
document.querySelectorAll('.mode-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    setMode(btn.dataset.mode);
    if (btn.dataset.mode === 'expert') {
      setTimeout(() => scrollToAnchor('#expert-workspace'), 60);
    }
  });
});

function refreshModeUI() {
  const m = MODE.current;
  const gate = document.getElementById('student-gate');
  const session = getStudentSession();
  // Predictor sub-elements
  const predictor = document.getElementById('predictor');
  const submitCard = document.getElementById('submitRequestCard');
  const studentBanner = document.getElementById('studentSessionBanner');
  const expertBanner = document.getElementById('expertActiveBanner');

  if (m === 'student') {
    // Student mode: gate visible if no session; predictor hidden until session.
    if (gate) gate.style.display = session ? 'none' : '';
    if (predictor) predictor.style.display = session ? '' : 'none';
    if (studentBanner) studentBanner.style.display = session ? 'flex' : 'none';
    if (expertBanner) expertBanner.style.display = 'none';
    setPredictorEditable(false); // student → read-only
    if (session) populatePredictorFromSession(session);
    updateSubmitRequestUI(session);
  } else {
    // Expert mode: gate hidden; predictor visible; expert banner shows when active request loaded
    if (gate) gate.style.display = 'none';
    if (predictor) predictor.style.display = '';
    if (studentBanner) studentBanner.style.display = 'none';
    if (expertBanner) expertBanner.style.display = MODE.activeRequest ? 'flex' : 'none';
    setPredictorEditable(true); // expert → fully editable
    refreshExpertUI();
  }
}

function setPredictorEditable(editable) {
  // Lock/unlock predictor inputs based on mode
  const ids = ['dMaths','dPhysics','dChem','dCommunity'];
  ids.forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    el.disabled = !editable;
    el.classList.toggle('input-locked', !editable);
  });
}

// === Student session ===
function getStudentSession() {
  try {
    const raw = localStorage.getItem(SESSION_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch(e){ return null; }
}
function setStudentSession(s) {
  try { localStorage.setItem(SESSION_KEY, JSON.stringify(s)); } catch(e){}
}
function clearStudentSession() {
  try { localStorage.removeItem(SESSION_KEY); } catch(e){}
}

function populatePredictorFromSession(s) {
  if (!s) return;
  const setVal = (id, v) => { const el = document.getElementById(id); if (el && v != null && v !== '') el.value = v; };
  setVal('dMaths', s.maths);
  setVal('dPhysics', s.physics);
  setVal('dChem', s.chem);
  setVal('dCommunity', (s.community || 'oc').toLowerCase());
  // Update banner
  const sbName = document.getElementById('sbName');
  const sbReqId = document.getElementById('sbReqId');
  if (sbName) sbName.textContent = s.name || 'Student';
  if (sbReqId) sbReqId.textContent = s.requestId || '—';
  // Refresh dashboard
  if (typeof dashboardRefresh === 'function') dashboardRefresh();
}

function updateSubmitRequestUI(session) {
  const card = document.getElementById('submitRequestCard');
  const btn = document.getElementById('submitRequestBtn');
  const status = document.getElementById('submitRequestStatus');
  if (!card) return;
  if (!session) {
    card.style.display = 'none';
    return;
  }
  card.style.display = '';
  const submitted = session.requestSubmitted;
  if (submitted) {
    btn.disabled = true;
    btn.textContent = '✓ Request submitted';
    status.classList.add('status-submitted');
    status.textContent = `Status: submitted on ${new Date(submitted).toLocaleDateString('en-GB', {day:'numeric', month:'short'})}`;
  } else {
    btn.disabled = false;
    btn.innerHTML = 'Submit my request <span class="arrow">→</span>';
    status.classList.remove('status-submitted');
    status.textContent = 'Status: not yet submitted';
  }
}

// === Cutoff calculator for gate ===
function calcGateCutoff() {
  const m = parseFloat(document.getElementById('gMaths')?.value);
  const p = parseFloat(document.getElementById('gPhysics')?.value);
  const c = parseFloat(document.getElementById('gChem')?.value);
  const display = document.getElementById('gCutoffDisplay');
  if (!display) return;
  if (!isNaN(m) && !isNaN(p) && !isNaN(c) && m>=0 && m<=100 && p>=0 && p<=100 && c>=0 && c<=100) {
    const cutoff = m + p/2 + c/2;
    display.textContent = cutoff.toFixed(1);
  } else {
    display.textContent = '—';
  }
}
['gMaths','gPhysics','gChem'].forEach(id => {
  document.getElementById(id)?.addEventListener('input', calcGateCutoff);
});

// === Gate form submission ===
const gateForm = document.getElementById('gateForm');
gateForm?.addEventListener('submit', async (e) => {
  e.preventDefault();
  const errEl = document.getElementById('gError');
  errEl.textContent = '';
  const v = (id) => document.getElementById(id).value.trim();
  const data = {
    name: v('gName'),
    school: v('gSchool'),
    email: v('gEmail'),
    phone: v('gPhone'),
    maths: v('gMaths'),
    physics: v('gPhysics'),
    chem: v('gChem'),
    community: v('gCommunity'),
    city: v('gCity'),
    parentPhone: v('gParentPhone'),
    notes: v('gNotes'),
  };
  // Validate required
  const required = ['name','email','phone','maths','physics','chem','community'];
  for (const k of required) {
    if (!data[k]) {
      errEl.textContent = `Please fill in: ${k.charAt(0).toUpperCase()+k.slice(1)}`;
      return;
    }
  }
  // Email format
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) {
    errEl.textContent = 'Please enter a valid email address.';
    return;
  }
  // Numeric ranges
  for (const k of ['maths','physics','chem']) {
    const n = parseFloat(data[k]);
    if (isNaN(n) || n < 0 || n > 100) {
      errEl.textContent = `${k.charAt(0).toUpperCase()+k.slice(1)} must be a number between 0 and 100.`;
      return;
    }
  }
  // Compute cutoff
  data.cutoff = parseFloat(data.maths) + parseFloat(data.physics)/2 + parseFloat(data.chem)/2;
  // Generate request ID locally
  const ts = Date.now();
  const rand = Math.floor(Math.random()*0xFFFF).toString(16).padStart(4,'0').toUpperCase();
  data.requestId = `EA-2026-${new Date().toISOString().slice(0,10).replace(/-/g,'')}-${rand}`;
  data.submittedAt = new Date().toISOString();
  data.status = 'new';
  // Save session
  setStudentSession(data);
  // POST to the site lead DB (best-effort, don't block UX if it fails)
  if (true) {
    try {
      await fetch('/api/leads?source=tnea_expert', {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify({ action: 'submit_lead', payload: data })
      });
    } catch (err) { console.warn('Apps Script POST failed:', err); }
  }
  // Update UI
  refreshModeUI();
  setTimeout(() => scrollToAnchor('#predictor'), 80);
});

// === Sign out (clear session) ===
document.getElementById('sbLogout')?.addEventListener('click', () => {
  if (confirm('Sign out and clear your saved details? You\'ll need to fill the form again to see your predictions.')) {
    clearStudentSession();
    refreshModeUI();
    scrollToAnchor('#student-gate');
  }
});

// === Submit Request to Expert ===
document.getElementById('submitRequestBtn')?.addEventListener('click', async () => {
  const session = getStudentSession();
  if (!session) { alert('Please complete your details first.'); return; }
  const btn = document.getElementById('submitRequestBtn');
  btn.disabled = true;
  btn.innerHTML = '⏳ Submitting…';
  // Update local session
  session.requestSubmitted = new Date().toISOString();
  session.status = 'submitted';
  setStudentSession(session);
  // POST update to Apps Script
  if (APPS_SCRIPT_URL) {
    try {
      await fetch(APPS_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify({ action: 'submit_request', requestId: session.requestId, status: 'submitted' })
      });
    } catch (err) { console.warn('Submit-request POST failed:', err); }
  }
  updateSubmitRequestUI(session);
  alert(`Request submitted!\n\nYour request ID: ${session.requestId}\n\nAn EduAakashaa counsellor will email your full PDF report from info@eduaakashaa.com within 24 hours.`);
});

// === Expert PIN authentication ===
function setExpertAuthed(authed) {
  MODE.expertAuthed = authed;
  document.getElementById('expertPinCard').style.display = authed ? 'none' : '';
  document.getElementById('expertPanel').style.display = authed ? '' : 'none';
  try {
    if (authed) sessionStorage.setItem(EXPERT_KEY, '1');
    else sessionStorage.removeItem(EXPERT_KEY);
  } catch(e){}
}
document.getElementById('expertPinSubmit')?.addEventListener('click', () => {
  const pin = document.getElementById('expertPin').value;
  const err = document.getElementById('expertPinError');
  if (pin === EXPERT_PIN) {
    err.textContent = '';
    setExpertAuthed(true);
    refreshExpertUI();
  } else {
    err.textContent = 'Incorrect PIN. Please try again.';
    document.getElementById('expertPin').value = '';
  }
});
document.getElementById('expertPin')?.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') document.getElementById('expertPinSubmit').click();
});
document.getElementById('expertLogout')?.addEventListener('click', () => {
  if (confirm('Sign out from the Expert workspace?')) {
    setExpertAuthed(false);
    MODE.activeRequest = null;
    setMode('student');
  }
});

// === Expert request list (loaded from Apps Script) ===
async function fetchRequests() {
  if (!APPS_SCRIPT_URL) {
    return [
      // Demo data shown when no Apps Script URL is configured.
      { requestId:'EA-2026-DEMO-0001', name:'Demo Student', email:'demo@example.com', phone:'+91 ……', cutoff:197.5, community:'OC', maths:99, physics:99, chem:98, status:'submitted', submittedAt:new Date().toISOString(), notes:'Demo row — configure APPS_SCRIPT_URL to load real data.' },
    ];
  }
  try {
    const res = await fetch(APPS_SCRIPT_URL + '?action=list_requests&pin=' + encodeURIComponent(EXPERT_PIN));
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const data = await res.json();
    return Array.isArray(data) ? data : (data.requests || []);
  } catch (err) {
    console.error('fetchRequests failed:', err);
    return null;
  }
}

async function refreshExpertUI() {
  if (MODE.current !== 'expert' || !MODE.expertAuthed) return;
  const tbody = document.getElementById('requestsBody');
  if (!tbody) return;
  tbody.innerHTML = '<tr><td colspan="7" class="requests-empty">⏳ Loading requests…</td></tr>';
  const list = await fetchRequests();
  MODE.allRequests = list || [];
  renderRequestsTable();
}
document.getElementById('expertRefresh')?.addEventListener('click', refreshExpertUI);

function renderRequestsTable() {
  const tbody = document.getElementById('requestsBody');
  if (!tbody) return;
  let list = MODE.allRequests || [];
  if (list === null) {
    tbody.innerHTML = '<tr><td colspan="7" class="requests-empty">⚠ Could not reach Apps Script. Check APPS_SCRIPT_URL and EXPERT_PIN in the page source, then click Refresh.</td></tr>';
    return;
  }
  // Filters
  const search = (document.getElementById('requestsSearch')?.value || '').toLowerCase();
  const filter = document.getElementById('requestsFilter')?.value || 'all';
  if (search) list = list.filter(r =>
    (r.name||'').toLowerCase().includes(search) ||
    (r.email||'').toLowerCase().includes(search) ||
    (r.requestId||'').toLowerCase().includes(search)
  );
  if (filter !== 'all') list = list.filter(r => (r.status || 'new') === filter);
  if (list.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" class="requests-empty">No matching requests. Try clearing the search or status filter.</td></tr>';
    return;
  }
  tbody.innerHTML = list.map(r => {
    const status = r.status || 'new';
    const date = r.submittedAt ? new Date(r.submittedAt).toLocaleDateString('en-GB', {day:'numeric', month:'short', year:'numeric'}) : '—';
    return `<tr data-rid="${r.requestId}" class="${MODE.activeRequest && MODE.activeRequest.requestId === r.requestId ? 'requests-row-active' : ''}">
      <td><strong>${r.requestId || '—'}</strong></td>
      <td>${r.name || '—'}</td>
      <td>${r.email || '—'}</td>
      <td>${r.cutoff != null ? r.cutoff : '—'}</td>
      <td>${(r.community || '—').toString().toUpperCase()}</td>
      <td>${date}</td>
      <td><span class="req-status-pill req-status-${status}">${status}</span></td>
    </tr>`;
  }).join('');
  // Wire row clicks
  tbody.querySelectorAll('tr[data-rid]').forEach(tr => {
    tr.addEventListener('click', () => loadRequestForExpert(tr.dataset.rid));
  });
}
document.getElementById('requestsSearch')?.addEventListener('input', renderRequestsTable);
document.getElementById('requestsFilter')?.addEventListener('change', renderRequestsTable);

function loadRequestForExpert(rid) {
  const r = (MODE.allRequests || []).find(x => x.requestId === rid);
  if (!r) return;
  MODE.activeRequest = r;
  // Populate predictor inputs
  if (r.maths) document.getElementById('dMaths').value = r.maths;
  if (r.physics) document.getElementById('dPhysics').value = r.physics;
  if (r.chem) document.getElementById('dChem').value = r.chem;
  if (r.community) document.getElementById('dCommunity').value = r.community.toLowerCase();
  if (typeof dashboardRefresh === 'function') dashboardRefresh();
  // Show banners
  document.getElementById('ebReqId').textContent = r.requestId;
  document.getElementById('ebName').textContent = r.name || '—';
  document.getElementById('ebEmail').textContent = r.email || '—';
  document.getElementById('ebStatus').textContent = r.status || 'new';
  document.getElementById('elName').textContent = r.name || '—';
  document.getElementById('elMeta').textContent = `${r.requestId} · cutoff ${r.cutoff} · ${r.community || '—'}`;
  document.getElementById('expertActiveBanner').style.display = 'flex';
  document.getElementById('expertLoadedBanner').style.display = 'flex';
  document.getElementById('expertCtaRow').style.display = '';
  // Re-render table to highlight active row
  renderRequestsTable();
  // Scroll to predictor for editing
  setTimeout(() => scrollToAnchor('#predictor'), 60);
}

document.getElementById('elClose')?.addEventListener('click', () => {
  MODE.activeRequest = null;
  document.getElementById('expertActiveBanner').style.display = 'none';
  document.getElementById('expertLoadedBanner').style.display = 'none';
  document.getElementById('expertCtaRow').style.display = 'none';
  renderRequestsTable();
});
document.getElementById('ebClose')?.addEventListener('click', () => document.getElementById('elClose').click());

// === Expert PDF/Drive/Send actions ===
document.getElementById('expertGenPdf')?.addEventListener('click', () => {
  if (!MODE.activeRequest) { alert('Please select a request first.'); return; }
  generatePDFReport({ studentRequest: MODE.activeRequest });
});
document.getElementById('expertSavePdf')?.addEventListener('click', async () => {
  if (!MODE.activeRequest) { alert('Please select a request first.'); return; }
  if (!APPS_SCRIPT_URL) {
    alert('APPS_SCRIPT_URL is not configured. Edit the page source to add your Apps Script URL — see google_sheets_setup.md for the deployment guide.');
    return;
  }
  alert('Save-to-Drive: open the PDF first using Generate PDF, then in the print dialog choose "Save as PDF" → upload to your EduAakashaa Drive folder. The Apps Script integration to upload directly is documented in google_sheets_setup.md.');
});
document.getElementById('expertSendPdf')?.addEventListener('click', async () => {
  if (!MODE.activeRequest) { alert('Please select a request first.'); return; }
  if (!APPS_SCRIPT_URL) {
    alert('APPS_SCRIPT_URL is not configured. Edit the page source to add your Apps Script URL — see google_sheets_setup.md.');
    return;
  }
  if (!confirm(`Email the PDF report to ${MODE.activeRequest.email} from info@eduaakashaa.com?`)) return;
  try {
    const res = await fetch(APPS_SCRIPT_URL, {
      method: 'POST',
      mode: 'no-cors',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify({
        action: 'send_report',
        requestId: MODE.activeRequest.requestId,
        toEmail: MODE.activeRequest.email,
        toName: MODE.activeRequest.name,
      })
    });
    alert(`Send request submitted for ${MODE.activeRequest.requestId}.\n\nThe Apps Script will email the report from info@eduaakashaa.com and update the request status to "sent".`);
    MODE.activeRequest.status = 'sent';
    document.getElementById('ebStatus').textContent = 'sent';
    refreshExpertUI();
  } catch (err) {
    alert('Could not reach Apps Script. Please check the URL and try again.');
  }
});

// === Init: restore mode + session on page load ===
(function initSessionAndMode(){
  // Restore expert auth
  try {
    if (sessionStorage.getItem(EXPERT_KEY) === '1') MODE.expertAuthed = true;
  } catch(e){}
  if (MODE.expertAuthed) setExpertAuthed(true);
  // Restore mode (default student)
  let storedMode = 'student';
  try { storedMode = localStorage.getItem(MODE_KEY) || 'student'; } catch(e){}
  if (storedMode !== 'student' && storedMode !== 'expert') storedMode = 'student';
  setMode(storedMode);
})();


// === PDF REPORT GENERATOR ===
function generatePDFReport(opts){
  opts = opts || {};
  const ci = COMM_IDX[DASH.community];
  const date = new Date().toLocaleDateString('en-GB', { day:'numeric', month:'long', year:'numeric' });
  const dateISO = new Date().toISOString().split('T')[0];

  // Determine student context — use expert's active request if present, else the student session
  const sessionData = opts.studentRequest || getStudentSession() || null;
  const reportFor = sessionData ? {
    name: sessionData.name || '—',
    email: sessionData.email || '—',
    phone: sessionData.phone || '—',
    school: sessionData.school || '—',
    city: sessionData.city || '—',
    requestId: sessionData.requestId || '—',
    parentPhone: sessionData.parentPhone || '—',
    notes: sessionData.notes || '',
  } : {
    name:'—', email:'—', phone:'—', school:'—', city:'—', requestId:'—', parentPhone:'—', notes:''
  };

  // Get top 15 reachable
  const reachable = TNEA_DATA.records
    .filter(r => r[ci] != null && r[ci] <= DASH.cutoff + 2)
    .sort((a,b)=> b[ci] - a[ci])
    .slice(0, 15);

  // Compute college ranks
  const { rankByCollege, totalRanked } = computeCollegeRanks();

  // Rank trade-off rows
  const RANK_BRANCHES = ['CS','AM','AD','IT','EC','SC','EE','CE','ME','BM','CH'];
  const rankRows = [];
  for(const bcode of RANK_BRANCHES){
    const bIdx = bIdxByCode(bcode);
    if(bIdx < 0) continue;
    const reachableForBranch = TNEA_DATA.records.filter(r =>
      r[1] === bIdx && r[ci] != null && r[ci] <= DASH.cutoff + 2
    );
    if(reachableForBranch.length === 0){ rankRows.push({code:bcode, bestRank:null}); continue; }
    let best = null, bestRank = Infinity;
    for(const r of reachableForBranch){
      const rk = rankByCollege[r[0]];
      if(rk != null && rk < bestRank){ bestRank = rk; best = r; }
    }
    if(best) rankRows.push({ code:bcode, bestRank, college:TNEA_DATA.colleges[best[0]], cutoff:best[ci] });
  }
  rankRows.sort((a,b)=>{
    if(a.bestRank == null && b.bestRank == null) return 0;
    if(a.bestRank == null) return 1;
    if(b.bestRank == null) return -1;
    return a.bestRank - b.bestRank;
  });

  // Branch race
  const RACE_BRANCHES = ['CS','AM','AD','IT','EC','SC','EE','BM','ME','CE','CH','AE','AG'];
  const raceRows = [];
  for(const bc of RACE_BRANCHES){
    const bIdx = bIdxByCode(bc);
    if(bIdx<0) continue;
    const all = TNEA_DATA.records.filter(r=> r[1]===bIdx && r[ci]!=null);
    const reach = all.filter(r=> r[ci] <= DASH.cutoff + 2);
    if(all.length === 0) continue;
    raceRows.push({ bc, name:bNameByCode(bc), total:all.length, reach:reach.length, pct: Math.round(reach.length/all.length*100) });
  }

  // Counsellor commentary
  let commentary;
  if(DASH.cutoff >= 195){
    commentary = `Your cutoff of <strong>${DASH.cutoff}</strong> places you in <strong>premier-tier territory</strong>. CEG Guindy, MIT Chromepet and PSG Tech are realistic targets for CSE/ECE. Your strategy: prioritise college brand within your top 3-5 choices; CSE at any of these institutions is functionally interchangeable from a placement standpoint.`;
  } else if(DASH.cutoff >= 188){
    commentary = `Your cutoff of <strong>${DASH.cutoff}</strong> is <strong>strong</strong> — you have access to second-tier government and top private colleges. Likely shortlist: PSG Tech (lower CSE branches), CIT Coimbatore, GCT, TCE Madurai, Anna University regional campuses. CSE at PSG / CIT may be a stretch; ECE / IT / EEE more likely.`;
  } else if(DASH.cutoff >= 175){
    commentary = `Your cutoff of <strong>${DASH.cutoff}</strong> is the <strong>genuine breaking-point zone</strong> — the trade-off between college tier and computing branch is sharpest here. Concrete advice: list 2-3 top-tier colleges' core branches (ME/EE) FIRST, then 4-5 mid-tier private colleges' CSE/IT, then mid-tier core. Often a core branch at PSG/CIT/GCT outperforms CSE at a tier-3 self-financing college.`;
  } else {
    commentary = `Your cutoff of <strong>${DASH.cutoff}</strong> opens up the broad self-financing field. The single most important decision now is <strong>filtering by NAAC accreditation, NBA branch accreditation, and verified 2024 placement data</strong>. Brand recall on a "CSE" tag at an unaccredited college is worth less than a core branch at an autonomous, NBA-accredited mid-tier college.`;
  }

  // Rank gap insight
  const cseRows = rankRows.filter(r => r.bestRank != null && ['CS','AM','AD','IT','SC'].includes(r.code));
  const coreRows = rankRows.filter(r => r.bestRank != null && ['ME','CE','EE','BM'].includes(r.code));
  let gapInsight = '';
  if(cseRows.length && coreRows.length){
    const cseBest = cseRows.reduce((m,r)=>r.bestRank<m.bestRank?r:m, cseRows[0]);
    const coreBest = coreRows.reduce((m,r)=>r.bestRank<m.bestRank?r:m, coreRows[0]);
    const gap = cseBest.bestRank - coreBest.bestRank;
    if(gap > 0){
      gapInsight = `<p class="rpt-insight"><strong>Key insight:</strong> Your best <strong>${coreBest.code}</strong> option is <strong>rank #${coreBest.bestRank}</strong> (${coreBest.college.n}). Your best <strong>${cseBest.code}</strong> option is <strong>rank #${cseBest.bestRank}</strong> (${cseBest.college.n}). That is a <strong>${gap}-rank college-quality gap</strong> as the price of insisting on the computing branch.</p>`;
    }
  }

  // Build HTML report
  const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>EduAakashaa TNEA 2026 — Personalised Report (${dateISO})</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400..900&family=Plus+Jakarta+Sans:wght@300..800&family=JetBrains+Mono:wght@400..600&display=swap" rel="stylesheet">
<style>
  *{box-sizing:border-box;margin:0;padding:0}
  :root{
    --navy:#0E3A8A;--navy-deep:#0A2560;--navy-ink:#071A44;--orange:#FF6B0A;--orange-soft:#FF8A3D;
    --cream:#FBF7EE;--cream-2:#F5EFDF;--paper:#FFFDF7;--ink:#0E1B3D;--muted:#5A6278;--hairline:#E8DFC8;
    --green:#1F8B5C;--red:#C23A3A;
  }
  html,body{background:var(--cream);font-family:'Plus Jakarta Sans',sans-serif;color:var(--ink);line-height:1.55;font-size:13px}
  .rpt-page{max-width:760px;margin:0 auto;padding:30px 36px;background:#fff;min-height:100vh}
  /* Header band */
  .rpt-header{
    background:linear-gradient(135deg,var(--navy-ink) 0%,var(--navy) 100%);color:#fff;
    border-radius:14px;padding:24px 28px;margin-bottom:24px;display:grid;
    grid-template-columns:auto 1fr auto;gap:20px;align-items:center;
    border-left:5px solid var(--orange);
  }
  .rpt-logo{
    width:64px;height:64px;background:var(--orange);border-radius:14px;
    display:flex;align-items:center;justify-content:center;
    font-family:'Fraunces',serif;font-weight:700;font-size:24px;color:#fff;letter-spacing:-0.02em;
  }
  .rpt-logo-img{
    width:64px;height:64px;border-radius:14px;background:#fff;padding:6px;
    object-fit:contain;
  }
  /* Expert counselling CTA card — prominent, before footer */
  .rpt-expert-cta{
    background:linear-gradient(135deg,var(--orange) 0%,#E55D00 100%);color:#fff;
    border-radius:14px;padding:24px 28px;margin:24px 0;
    display:grid;grid-template-columns:1fr auto;gap:24px;align-items:center;
    box-shadow:0 4px 16px rgba(255,107,10,.18);page-break-inside:avoid;position:relative;overflow:hidden;
  }
  .rpt-expert-cta::before{
    content:"";position:absolute;right:-80px;top:-80px;width:240px;height:240px;
    background:radial-gradient(circle,rgba(255,255,255,.15) 0%,transparent 65%);border-radius:50%;
  }
  .rpt-expert-cta-text{position:relative;z-index:2}
  .rpt-expert-cta-eyebrow{
    font-family:'JetBrains Mono',monospace;font-size:10px;letter-spacing:.18em;text-transform:uppercase;
    font-weight:700;color:rgba(255,255,255,.85);margin-bottom:8px;
  }
  .rpt-expert-cta h3{
    font-family:'Fraunces',serif;font-size:22px;font-weight:600;letter-spacing:-0.02em;
    color:#fff;margin:0 0 8px;line-height:1.2;
  }
  .rpt-expert-cta h3 em{font-style:italic;color:#FFE9D6}
  .rpt-expert-cta p{font-size:13px;line-height:1.5;color:rgba(255,255,255,.92);margin:0;max-width:520px}
  .rpt-expert-cta-actions{display:flex;flex-direction:column;gap:8px;position:relative;z-index:2}
  .rpt-cta-btn{
    display:inline-flex;align-items:center;gap:10px;padding:11px 18px;
    background:#fff;color:var(--navy-ink);text-decoration:none;border-radius:8px;
    font-family:'Plus Jakarta Sans',sans-serif;font-size:13px;font-weight:700;letter-spacing:.01em;
    white-space:nowrap;border:1.5px solid rgba(255,255,255,.3);
  }
  .rpt-cta-btn.whatsapp{background:#25D366;color:#fff}
  .rpt-cta-btn.email{background:rgba(255,255,255,.15);color:#fff;border-color:rgba(255,255,255,.4)}
  .rpt-cta-btn-icon{font-size:16px}

  /* QR codes panel inside the PDF report */
  .rpt-qr-section{
    background:var(--cream-2);border:1px solid var(--hairline);border-radius:14px;
    padding:22px 26px;margin:18px 0;page-break-inside:avoid;
  }
  .rpt-qr-head{margin-bottom:14px}
  .rpt-qr-eyebrow{
    font-family:'JetBrains Mono',monospace;font-size:10px;letter-spacing:.18em;
    text-transform:uppercase;color:var(--orange);font-weight:700;margin-bottom:4px;
  }
  .rpt-qr-head h3{
    font-family:'Fraunces',serif;font-size:18px;font-weight:600;color:var(--navy-ink);
    letter-spacing:-.02em;margin:0;line-height:1.25;
  }
  .rpt-qr-grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}
  .rpt-qr-card{
    background:#fff;border:1px solid var(--hairline);border-radius:10px;
    padding:14px 16px;display:flex;flex-direction:column;align-items:center;gap:8px;
    text-align:center;border-top:3px solid var(--orange);
  }
  .rpt-qr-card-wa{border-top-color:#25D366}
  .rpt-qr-card-label{
    font-family:'JetBrains Mono',monospace;font-size:9.5px;font-weight:700;letter-spacing:.14em;
    text-transform:uppercase;color:var(--navy-ink);
  }
  .rpt-qr-img-wrap{
    background:#fff;padding:6px;border-radius:6px;
    width:140px;height:140px;display:flex;align-items:center;justify-content:center;
  }
  .rpt-qr-img{max-width:100%;max-height:100%;display:block}
  .rpt-qr-card-caption{
    font-size:11px;color:var(--muted);font-style:italic;
  }
  .rpt-brand-name{font-family:'Fraunces',serif;font-size:28px;font-weight:600;letter-spacing:-0.02em;line-height:1}
  .rpt-brand-name span{color:var(--orange-soft)}
  .rpt-brand-tag{font-family:'JetBrains Mono',monospace;font-size:9.5px;letter-spacing:.18em;text-transform:uppercase;color:rgba(255,255,255,.7);margin-top:4px}
  .rpt-meta{text-align:right;font-family:'JetBrains Mono',monospace;font-size:10.5px;color:rgba(255,255,255,.85);letter-spacing:.06em}
  .rpt-meta strong{color:var(--orange-soft);font-weight:700;letter-spacing:.04em}

  /* === COVER PAGE (Page 1) === */
  .rpt-cover{
    page-break-after:always;display:grid;grid-template-columns:1fr 1fr;gap:24px;align-items:start;
    background:var(--paper);border:1px solid var(--hairline);border-radius:14px;
    padding:24px;margin-bottom:24px;
  }
  .rpt-cover-poster img{width:100%;height:auto;border-radius:10px;display:block;box-shadow:0 4px 12px rgba(14,27,61,.12)}
  .rpt-cover-meta{display:flex;flex-direction:column;gap:14px}
  .rpt-cover-eyebrow{
    display:inline-block;font-family:'JetBrains Mono',monospace;font-size:10px;letter-spacing:.18em;
    text-transform:uppercase;color:var(--orange);font-weight:700;
    background:#FFF2E8;padding:6px 12px;border-radius:6px;width:fit-content;
  }
  .rpt-cover-title{
    font-family:'Fraunces',serif;font-size:28px;font-weight:600;color:var(--navy-ink);
    letter-spacing:-.025em;line-height:1.15;margin:0;
  }
  .rpt-cover-title em{color:var(--orange);font-style:italic;font-weight:500}
  .rpt-cover-detail{width:100%;border-collapse:collapse;font-size:11.5px}
  .rpt-cover-detail td{padding:8px 10px;border-bottom:1px solid var(--hairline);vertical-align:top}
  .rpt-cover-detail tr td:first-child{
    font-family:'JetBrains Mono',monospace;font-size:9.5px;letter-spacing:.08em;
    text-transform:uppercase;color:var(--muted);width:42%;font-weight:600;
  }
  .rpt-cover-detail tr td:last-child{color:var(--navy-ink)}
  .rpt-cover-detail tr td strong{color:var(--navy-ink);font-weight:700}
  .rpt-cover-notes{
    background:var(--cream-2);border-left:3px solid var(--orange);
    padding:10px 12px;border-radius:6px;font-size:11.5px;color:var(--ink);
    line-height:1.5;
  }
  .rpt-cover-notes strong{color:var(--navy-ink)}

  /* === TABLE OF CONTENTS === */
  .rpt-toc{
    background:var(--cream-2);border:1px solid var(--hairline);border-radius:12px;
    padding:22px 26px;margin-bottom:22px;page-break-after:always;
  }
  .rpt-toc-eyebrow{
    font-family:'JetBrains Mono',monospace;font-size:10.5px;letter-spacing:.18em;
    text-transform:uppercase;color:var(--orange);font-weight:700;margin-bottom:6px;
  }
  .rpt-toc-title{
    font-family:'Fraunces',serif;font-size:18px;font-weight:600;color:var(--navy-ink);
    letter-spacing:-.02em;margin:0 0 14px;line-height:1.3;
  }
  .rpt-toc-list{list-style:none;padding:0;margin:0;counter-reset:toci;
    display:grid;grid-template-columns:1fr 1fr;gap:6px 22px;
  }
  .rpt-toc-list li{
    padding:8px 0;border-bottom:1px dotted var(--hairline);
    font-size:13px;color:var(--ink);position:relative;
  }
  .rpt-toc-list li a{
    color:var(--navy-ink);text-decoration:none;display:block;
    padding-left:4px;transition:color .15s;
  }
  .rpt-toc-list li a:hover{color:var(--orange)}
  @media print{
    .rpt-toc-list li a{color:var(--navy-ink) !important}
  }
  /* === Section anchors should leave a small offset when jumped to === */
  .rpt-section,.rpt-expert-cta,.rpt-qr-section,.rpt-footer{scroll-margin-top:60px}

  /* Section */
  .rpt-section{margin-bottom:22px;page-break-inside:avoid}
  .rpt-eyebrow{font-family:'JetBrains Mono',monospace;font-size:10px;letter-spacing:.18em;text-transform:uppercase;color:var(--orange);font-weight:700;margin-bottom:6px}
  .rpt-h2{font-family:'Fraunces',serif;font-size:20px;font-weight:600;color:var(--navy-ink);letter-spacing:-0.02em;margin-bottom:6px;line-height:1.25}
  .rpt-h2 em{color:var(--orange);font-style:italic;font-weight:500}
  .rpt-section > p{font-size:12.5px;color:var(--ink);line-height:1.6;margin-bottom:10px}
  /* AI disclaimer at top */
  .rpt-disclaimer{
    background:#FFF2E8;border-left:4px solid var(--orange);border-radius:8px;
    padding:14px 18px;margin-bottom:20px;font-size:12px;color:var(--ink);line-height:1.55;
  }
  .rpt-disclaimer strong{color:var(--navy-ink)}
  .rpt-disclaimer em{color:var(--orange);font-style:italic;font-weight:500}
  /* Profile card */
  .rpt-profile-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin-top:6px}
  .rpt-profile-cell{background:var(--cream-2);border:1px solid var(--hairline);border-radius:8px;padding:10px 12px}
  .rpt-profile-label{font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:.14em;text-transform:uppercase;color:var(--muted);font-weight:600;margin-bottom:3px}
  .rpt-profile-val{font-family:'Fraunces',serif;font-size:18px;font-weight:600;color:var(--navy-ink);letter-spacing:-0.02em;line-height:1}
  .rpt-profile-val.cutoff{color:var(--orange);font-size:22px}
  /* Tables */
  .rpt-table{width:100%;border-collapse:collapse;font-size:11px;margin-top:6px;border:1px solid var(--hairline);border-radius:8px;overflow:hidden}
  .rpt-table thead th{background:var(--navy-ink);color:#fff;padding:8px 10px;font-family:'JetBrains Mono',monospace;font-size:9.5px;font-weight:600;letter-spacing:.1em;text-transform:uppercase;text-align:left}
  .rpt-table thead th.num{text-align:right}
  .rpt-table tbody td{padding:7px 10px;border-bottom:1px solid var(--hairline);vertical-align:middle}
  .rpt-table tbody td.num{text-align:right;font-family:'JetBrains Mono',monospace;font-weight:600}
  .rpt-table tbody tr:nth-child(even){background:var(--cream)}
  .rpt-table .rk-pill{display:inline-block;font-family:'Fraunces',serif;font-weight:700;font-size:11px;padding:2px 7px;border-radius:5px;color:#fff;min-width:34px;text-align:center}
  .rk-1{background:#0E6B40}.rk-2{background:#1F8B5C}.rk-3{background:#E89A1C}.rk-4{background:var(--orange)}.rk-5{background:#9AA0AC}
  /* Race bars */
  .rpt-race{display:flex;flex-direction:column;gap:5px;margin-top:6px}
  .rpt-race-row{display:grid;grid-template-columns:160px 1fr 60px;gap:10px;align-items:center;font-size:11px}
  .rpt-race-name{color:var(--navy-ink);font-weight:600}
  .rpt-race-track{height:8px;background:var(--cream-2);border-radius:4px;overflow:hidden;border:1px solid var(--hairline)}
  .rpt-race-fill{height:100%;border-radius:4px}
  .rpt-race-pct{font-family:'JetBrains Mono',monospace;font-weight:700;color:var(--navy-ink);font-size:11px;text-align:right}
  .rpt-race-fill.ok{background:linear-gradient(90deg,var(--green) 0%,#3DAA76 100%)}
  .rpt-race-fill.mid{background:linear-gradient(90deg,#E89A1C 0%,#F0B040 100%)}
  .rpt-race-fill.weak{background:linear-gradient(90deg,var(--orange) 0%,var(--orange-soft) 100%)}
  /* Insight */
  .rpt-insight{
    background:var(--cream-2);border-left:3px solid var(--orange);
    padding:12px 16px;border-radius:8px;font-size:12px;line-height:1.6;margin-top:10px;
  }
  .rpt-insight strong{color:var(--navy-ink)}
  /* Verdict */
  .rpt-verdict{
    background:linear-gradient(135deg,var(--navy-ink) 0%,var(--navy) 100%);color:#fff;
    border-radius:10px;padding:18px 22px;margin-top:8px;
  }
  .rpt-verdict-label{font-family:'JetBrains Mono',monospace;font-size:9.5px;letter-spacing:.18em;text-transform:uppercase;color:var(--orange-soft);margin-bottom:6px;font-weight:700}
  .rpt-verdict h4{font-family:'Fraunces',serif;font-size:15px;font-weight:600;margin-bottom:6px;color:#fff}
  .rpt-verdict p{font-size:12px;color:rgba(255,255,255,.92);line-height:1.6}
  .rpt-verdict strong{color:#fff;background:rgba(255,107,10,.25);padding:1px 5px;border-radius:3px}
  /* Tips */
  .rpt-tips-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:6px}
  .rpt-tip{background:var(--cream-2);border:1px solid var(--hairline);border-radius:8px;padding:10px 14px;display:flex;gap:10px}
  .rpt-tip-num{
    width:22px;height:22px;background:var(--navy-ink);color:var(--orange);border-radius:5px;
    display:flex;align-items:center;justify-content:center;font-family:'Fraunces',serif;
    font-weight:700;font-size:11px;flex-shrink:0;
  }
  .rpt-tip h5{font-size:12px;color:var(--navy-ink);margin-bottom:3px;line-height:1.3}
  .rpt-tip p{font-size:10.5px;color:var(--muted);line-height:1.5}
  /* Footer */
  .rpt-footer{
    margin-top:30px;padding:20px 22px;background:linear-gradient(135deg,var(--navy-ink) 0%,var(--navy) 100%);
    color:#fff;border-radius:12px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:18px;
  }
  .rpt-footer-block strong{display:block;font-family:'JetBrains Mono',monospace;font-size:9.5px;letter-spacing:.18em;text-transform:uppercase;color:var(--orange-soft);margin-bottom:8px;font-weight:700}
  .rpt-footer-block a, .rpt-footer-block span{display:block;color:rgba(255,255,255,.92);font-size:11px;text-decoration:none;padding:2px 0;line-height:1.5}
  .rpt-footer-block a:hover{color:var(--orange-soft)}
  .rpt-final{font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:.1em;text-transform:uppercase;color:var(--muted);text-align:center;margin-top:14px;padding-top:14px;border-top:1px solid var(--hairline)}
  /* Print rules */
  .rpt-toolbar{
    position:fixed;top:0;left:0;right:0;background:var(--navy-ink);color:#fff;padding:10px 20px;
    display:flex;justify-content:space-between;align-items:center;z-index:1000;font-size:13px;
    box-shadow:0 2px 10px rgba(0,0,0,.15);
  }
  .rpt-toolbar-btn{
    background:var(--orange);color:#fff;border:none;padding:7px 18px;border-radius:6px;cursor:pointer;
    font-family:'Plus Jakarta Sans',sans-serif;font-weight:700;font-size:13px;
  }
  .rpt-toolbar-btn:hover{background:var(--orange-soft)}
  body.with-toolbar .rpt-page{margin-top:48px}
  @media print {
    .rpt-toolbar{display:none}
    body.with-toolbar .rpt-page{margin-top:0}
    .rpt-page{max-width:none;margin:0;padding:18mm 16mm;box-shadow:none}
    .rpt-section{page-break-inside:avoid}
    @page{size:A4;margin:0}
  }
</style>
</head>
<body class="with-toolbar">
<div class="rpt-toolbar">
  <span><strong>EduAakashaa Report</strong> — use Ctrl+P (Cmd+P on Mac) → "Save as PDF" to download.</span>
  <button class="rpt-toolbar-btn" onclick="window.print()">🖨 Print / Save as PDF</button>
</div>

<div class="rpt-page">
  <header class="rpt-header">
    <img class="rpt-logo-img" src="${IMG.logo}" alt="EduAakashaa">
    <div>
      <div class="rpt-brand-name">Edu<span>Aakashaa</span></div>
      <div class="rpt-brand-tag">Guiding students towards the right future</div>
    </div>
    <div class="rpt-meta">
      <div><strong>TNEA 2026</strong></div>
      <div>Personalised Report</div>
      <div>${date}</div>
    </div>
  </header>

  <!-- ====================== PAGE 1 — COVER ====================== -->
  <section class="rpt-cover">
    <div class="rpt-cover-poster">
      <img src="${IMG.poster}" alt="EduAakashaa TNEA 2026 Expert Guidance">
    </div>
    <div class="rpt-cover-meta">
      <div class="rpt-cover-eyebrow">📘 Personalised Report · TNEA 2026</div>
      <h1 class="rpt-cover-title">Prepared for <em>${reportFor.name}</em></h1>
      <table class="rpt-cover-detail">
        <tr><td>Request ID</td><td><strong>${reportFor.requestId}</strong></td></tr>
        <tr><td>School / college</td><td>${reportFor.school}</td></tr>
        <tr><td>City / district</td><td>${reportFor.city}</td></tr>
        <tr><td>Email</td><td>${reportFor.email}</td></tr>
        <tr><td>Phone</td><td>${reportFor.phone}</td></tr>
        <tr><td>Parent phone</td><td>${reportFor.parentPhone}</td></tr>
        <tr><td>Maths · Physics · Chemistry</td><td><strong>${DASH.marks.m} · ${DASH.marks.p} · ${DASH.marks.c}</strong></td></tr>
        <tr><td>Community</td><td><strong>${COMM_LABEL[DASH.community]}</strong></td></tr>
        <tr><td>TNEA Cutoff (out of 200)</td><td><strong style="color:var(--orange);font-size:18px">${DASH.cutoff}</strong></td></tr>
        <tr><td>Generated on</td><td>${date}</td></tr>
      </table>
      ${reportFor.notes ? `<div class="rpt-cover-notes"><strong>Student notes:</strong> ${reportFor.notes}</div>` : ''}
    </div>
  </section>

  <!-- ====================== TABLE OF CONTENTS ====================== -->
  <nav class="rpt-toc">
    <div class="rpt-toc-eyebrow">📑 Table of contents</div>
    <h3 class="rpt-toc-title">Use the section headings below to jump quickly through this report</h3>
    <ol class="rpt-toc-list">
      <li><a href="#sec-disclaimer">Section 01 · AI Disclaimer</a></li>
      <li><a href="#sec-profile">Section 02 · Cutoff &amp; Community Summary</a></li>
      <li><a href="#sec-top15">Section 03 · Top 15 Reachable Combinations</a></li>
      <li><a href="#sec-tradeoff">Section 04 · Branch Trade-Off Analysis</a></li>
      <li><a href="#sec-reachability">Section 05 · Branch Reachability</a></li>
      <li><a href="#sec-verdict">Section 06 · Counsellor Verdict</a></li>
      <li><a href="#sec-rules">Section 07 · Choice-Filling Rule Book</a></li>
      <li><a href="#sec-lookalikes">Section 08 · Lookalike College Names</a></li>
      <li><a href="#sec-counsel">Section 09 · Talk to a Counsellor</a></li>
      <li><a href="#sec-qr">Section 10 · Save This Dashboard (QR codes)</a></li>
      <li><a href="#sec-contact">Section 11 · EduAakashaa Contact &amp; Hours</a></li>
    </ol>
  </nav>

  <section class="rpt-section" id="sec-disclaimer">
    <div class="rpt-eyebrow">Section 01 · Important note before you read on</div>
    <h2 class="rpt-h2">AI-generated report — <em>cross-validate before acting</em></h2>
    <div class="rpt-disclaimer">
      <strong>⚠ This is an AI-generated report.</strong> All numbers are computed from the official TNEA 2025 cutoff dataset (cutoff.tneaonline.org), but the recommendations and rankings are produced algorithmically. <em>Always cross-validate with tneaonline.org and a qualified counsellor before locking in your TNEA choices.</em> EduAakashaa accepts no liability for decisions made from this AI output alone.
    </div>
  </section>

  <section class="rpt-section" id="sec-profile">
    <div class="rpt-eyebrow">Section 02 · Your Profile</div>
    <h2 class="rpt-h2">Cutoff and community summary</h2>
    <p>The dashboard input that produced this report:</p>
    <div class="rpt-profile-grid">
      <div class="rpt-profile-cell"><div class="rpt-profile-label">Maths</div><div class="rpt-profile-val">${DASH.marks.m}</div></div>
      <div class="rpt-profile-cell"><div class="rpt-profile-label">Physics</div><div class="rpt-profile-val">${DASH.marks.p}</div></div>
      <div class="rpt-profile-cell"><div class="rpt-profile-label">Chemistry</div><div class="rpt-profile-val">${DASH.marks.c}</div></div>
      <div class="rpt-profile-cell"><div class="rpt-profile-label">TNEA Cutoff</div><div class="rpt-profile-val cutoff">${DASH.cutoff}</div></div>
      <div class="rpt-profile-cell"><div class="rpt-profile-label">Community</div><div class="rpt-profile-val">${COMM_LABEL[DASH.community]}</div></div>
    </div>
  </section>

  <section class="rpt-section" id="sec-top15">
    <div class="rpt-eyebrow">Section 03 · Top 15 Reachable Combinations</div>
    <h2 class="rpt-h2">Your <em>realistic</em> college list (2025 actuals)</h2>
    <p>Sorted by closing cutoff, descending. These are the matches with the highest prestige among colleges within your reach. <strong>EA rank</strong> = EduAakashaa proprietary college rank (1 best, 388 last). <strong>NIRF</strong> = official 2024 Engineering ranking. <strong>NAAC</strong> = accreditation grade where verified.</p>
    <table class="rpt-table">
      <thead><tr><th>#</th><th>College</th><th>Branch</th><th class="num">EA</th><th class="num">NIRF</th><th class="num">NAAC</th><th class="num">Cutoff</th><th class="num">Buffer</th></tr></thead>
      <tbody>${reachable.map((r,i)=>{
        const c = TNEA_DATA.colleges[r[0]];
        const b = TNEA_DATA.branches[r[1]];
        const head = (DASH.cutoff - r[ci]).toFixed(1);
        const cn = c.n.length > 50 ? c.n.substring(0,50)+'…' : c.n;
        const n = NIRF_RANKS[r[0]];
        const nirfCell = n ? `<span style="background:${n.band==='top50'?'#0E6B40':n.band==='top100'?'#1F8B5C':n.band==='top200'?'#0E3A8A':'#5A6278'};color:#fff;padding:1px 6px;border-radius:4px;font-family:'JetBrains Mono',monospace;font-size:9px;font-weight:700">#${n.display}</span>` : '<span style="color:var(--muted);font-size:10px">—</span>';
        const ea = EA_RANK[r[0]];
        const eaCell = (ea && ea < 999) ? `<span style="background:${ea<=10?'#FFE9D6':ea<=50?'#E0EAFF':ea<=100?'#E6F5EE':'#F5EFDF'};color:${ea<=10?'#9A3D00':ea<=50?'#0E3A8A':ea<=100?'#0A4F2D':'#5A6278'};padding:1px 6px;border-radius:4px;font-family:'JetBrains Mono',monospace;font-size:9px;font-weight:700">#${ea}</span>` : '<span style="color:var(--muted);font-size:10px">—</span>';
        const naac = NAAC_GRADES[r[0]];
        const naacCell = naac ? `<span style="background:${naac==='A++'?'#0E6B40':naac==='A+'?'#1F8B5C':naac==='A'?'#0E3A8A':'#9A6B00'};color:#fff;padding:1px 6px;border-radius:4px;font-family:'JetBrains Mono',monospace;font-size:9px;font-weight:700">${naac}</span>` : '<span style="color:var(--muted);font-size:10px">—</span>';
        return `<tr><td>${i+1}</td><td>${cn}<br><span style="font-family:'JetBrains Mono',monospace;font-size:9px;color:var(--muted)">${c.d} · ${c.t}</span></td><td><strong>${b.c}</strong> ${b.n.substring(0,24)}</td><td class="num">${eaCell}</td><td class="num">${nirfCell}</td><td class="num">${naacCell}</td><td class="num">${r[ci]}</td><td class="num" style="color:${head>=3?'#0E6B40':head>=0?'#9A3D00':'#C23A3A'}">${head>0?'+':''}${head}</td></tr>`;
      }).join('')}</tbody>
    </table>
    <p style="font-size:10.5px;color:var(--muted);margin-top:8px;font-style:italic">EA = EduAakashaa proprietary rank · NIRF = National Institutional Ranking Framework Engineering 2024 (Ministry of Education, Aug 2024) · NAAC = National Assessment & Accreditation Council grade. Verify at <strong>nirfindia.org</strong> and the college's official website.</p>
  </section>

  <section class="rpt-section" id="sec-tradeoff">
    <div class="rpt-eyebrow">Section 04 · Branch Trade-Off Analysis</div>
    <h2 class="rpt-h2">Best-ranked college you can secure, <em>per branch</em></h2>
    <p>Colleges ranked 1 to ${totalRanked} in your community by their highest 2025 cutoff (rank #1 = most competitive). For each branch, this shows the best-ranked college that closed at or below your cutoff.</p>
    <table class="rpt-table">
      <thead><tr><th>Branch</th><th>Best Rank</th><th>Best College</th><th>District</th><th class="num">Cutoff</th></tr></thead>
      <tbody>${rankRows.map(r => {
        if(r.bestRank == null) return `<tr><td><strong>${r.code}</strong></td><td>—</td><td colspan="2"><em style="color:var(--muted)">No reachable college at this cutoff</em></td><td class="num">—</td></tr>`;
        const tier = r.bestRank<=10?1:r.bestRank<=30?2:r.bestRank<=60?3:r.bestRank<=120?4:5;
        const cn = r.college.n.length > 45 ? r.college.n.substring(0,45)+'…' : r.college.n;
        return `<tr><td><strong>${r.code}</strong></td><td><span class="rk-pill rk-${tier}">#${r.bestRank}</span></td><td>${cn}</td><td>${r.college.d}</td><td class="num">${r.cutoff}</td></tr>`;
      }).join('')}</tbody>
    </table>
    ${gapInsight}
  </section>

  <section class="rpt-section" id="sec-reachability">
    <div class="rpt-eyebrow">Section 05 · Branch Reachability</div>
    <h2 class="rpt-h2">How many colleges per branch are within reach</h2>
    <p>Percentage of TN colleges offering each branch where you can secure a seat at your cutoff.</p>
    <div class="rpt-race">${raceRows.sort((a,b)=>b.pct-a.pct).map(r => {
      const cls = r.pct>=60?'ok':r.pct>=30?'mid':'weak';
      return `<div class="rpt-race-row">
        <span class="rpt-race-name">${r.bc} · ${r.name.substring(0,18)}</span>
        <div class="rpt-race-track"><div class="rpt-race-fill ${cls}" style="width:${Math.max(r.pct,2)}%"></div></div>
        <span class="rpt-race-pct">${r.pct}% (${r.reach}/${r.total})</span>
      </div>`;
    }).join('')}</div>
  </section>

  <section class="rpt-section" id="sec-verdict">
    <div class="rpt-eyebrow">Section 06 · Counsellor Verdict</div>
    <h2 class="rpt-h2">EduAakashaa's reading at your cutoff</h2>
    <div class="rpt-verdict">
      <div class="rpt-verdict-label">Personalised commentary · cutoff ${DASH.cutoff} · ${COMM_LABEL[DASH.community]}</div>
      <p>${commentary}</p>
    </div>
  </section>

  <section class="rpt-section" id="sec-rules" style="page-break-before:always">
    <div class="rpt-eyebrow">Section 07 · Choice-Filling Rule Book</div>
    <h2 class="rpt-h2">8 rules to fill your TNEA choices <em>without losing a seat</em></h2>
    <p>The most expensive mistake in TNEA admissions isn't picking the wrong college — it's picking a college you didn't intend because two have similar names. Always type the 4-digit code first.</p>
    <div class="rpt-tips-grid">
      <div class="rpt-tip"><div class="rpt-tip-num">01</div><div><h5>Always type the 4-digit code first</h5><p>The portal autofills the college name once you enter the code. If the autofilled name doesn't match — stop and re-check.</p></div></div>
      <div class="rpt-tip"><div class="rpt-tip-num">02</div><div><h5>Sort choices in true preference order</h5><p>System auto-allocates the highest available choice. Don't list a "safe" college as #1 thinking you'll be bumped up — you won't.</p></div></div>
      <div class="rpt-tip"><div class="rpt-tip-num">03</div><div><h5>List 30–50 choices, not 10</h5><p>Round-1 cutoffs can be 1–2 marks higher than expected. List ambitious + realistic + safe in 1:2:2 ratio.</p></div></div>
      <div class="rpt-tip"><div class="rpt-tip-num">04</div><div><h5>Double-check the branch code</h5><p>"CS" (Computer Science) and "AM" (CSE — AI &amp; ML) are different programmes with different cutoffs. One letter changes everything.</p></div></div>
      <div class="rpt-tip"><div class="rpt-tip-num">05</div><div><h5>Verify NAAC and NBA per branch</h5><p>NAAC A++ at the institution doesn't mean every branch has NBA accreditation. NBA matters more for placements.</p></div></div>
      <div class="rpt-tip"><div class="rpt-tip-num">06</div><div><h5>Cross-check the location, not just the name</h5><p>"Government College of Engineering" appears 9 times across TN. "St. Joseph's" appears 4 times. Match the district AND street address.</p></div></div>
      <div class="rpt-tip"><div class="rpt-tip-num">07</div><div><h5>Save and review before final submission</h5><p>The portal lets you save and reopen. Print the saved list, sit with a parent or counsellor, walk through every code once.</p></div></div>
      <div class="rpt-tip"><div class="rpt-tip-num">08</div><div><h5>Don't blindly trust this AI tool</h5><p>This dashboard helps build a shortlist — it cannot replace verification on tneaonline.org or a counsellor's judgement.</p></div></div>
    </div>
  </section>

  <section class="rpt-section" id="sec-lookalikes">
    <div class="rpt-eyebrow">Section 08 · Lookalike College Names</div>
    <h2 class="rpt-h2">The names students mix up <em>every year</em></h2>
    <p>Always verify the 4-digit code. Examples from the official 2025 dataset:</p>
    <table class="rpt-table">
      <thead><tr><th>Code</th><th>College name</th><th>District</th></tr></thead>
      <tbody>
        <tr><td><strong style="color:var(--orange)">2718</strong></td><td><strong>Sri Krishna College of Engineering &amp; Technology</strong></td><td>Coimbatore</td></tr>
        <tr><td>1335</td><td>Sri Krishna Institute of Technology</td><td>Kancheepuram</td></tr>
        <tr><td>1427</td><td>Sri Krishna Engineering College</td><td>Kancheepuram</td></tr>
        <tr><td>1438</td><td>Sree Krishna College of Engineering</td><td>Vellore</td></tr>
        <tr><td>1526</td><td>Sri Krishna College of Engineering</td><td>Ranipet</td></tr>
        <tr><td>2719</td><td>Sri Ramakrishna Engineering College</td><td>Coimbatore</td></tr>
        <tr><td colspan="3" style="background:var(--cream-2);font-style:italic;color:var(--muted);font-size:11px">… and 9 colleges named exactly "Government College of Engineering" across TN. Each has different placement records.</td></tr>
      </tbody>
    </table>
  </section>

  <!-- EXPERT COUNSELLING CTA -->
  <div class="rpt-expert-cta" id="sec-counsel">
    <div class="rpt-expert-cta-text">
      <div class="rpt-expert-cta-eyebrow">Section 09 · ⭐ Expert Guidance Available</div>
      <h3>Don't fill <em>blindly</em> — talk to an EduAakashaa counsellor</h3>
      <p>Choice filling is a one-shot decision that shapes the next 4 years and your career trajectory. Our counsellors have guided 1,200+ TN families through TNEA, JOSAA, NEET-UG, and overseas admissions. Book a free 30-minute call — we'll review this report with you and build your final choice list.</p>
    </div>
    <div class="rpt-expert-cta-actions">
      <a href="https://wa.me/918015722706?text=Hi%2C%20I%20just%20generated%20my%20EduAakashaa%20TNEA%20report%20and%20would%20like%20to%20book%20a%20counselling%20call." class="rpt-cta-btn whatsapp"><span class="rpt-cta-btn-icon">💬</span> WhatsApp · +91 80157 22706</a>
      <a href="mailto:info@eduaakashaa.com?subject=TNEA%202026%20Counselling%20Request&body=Hi%20EduAakashaa%20team%2C%0A%0AI%20just%20generated%20my%20personalised%20TNEA%20report%20and%20would%20like%20to%20book%20a%20counselling%20call.%0A%0AMy%20cutoff%3A%20${DASH.cutoff}%0AMy%20community%3A%20${COMM_LABEL[DASH.community]}%0A%0APlease%20call%20me%20at%3A%20" class="rpt-cta-btn email"><span class="rpt-cta-btn-icon">✉️</span> Email · info@eduaakashaa.com</a>
      <a href="tel:+918015722706" class="rpt-cta-btn"><span class="rpt-cta-btn-icon">📞</span> Call · +91 80157 22706</a>
    </div>
  </div>

  <!-- QR CODES — bookmark + WhatsApp group -->
  <div class="rpt-qr-section" id="sec-qr">
    <div class="rpt-qr-head">
      <div class="rpt-qr-eyebrow">Section 10 · 📱 Scan & save</div>
      <h3>Two QRs to keep this dashboard, and our team, one tap away</h3>
    </div>
    <div class="rpt-qr-grid">
      <div class="rpt-qr-card">
        <div class="rpt-qr-card-label">📖 Bookmark this dashboard</div>
        <div class="rpt-qr-img-wrap"><img src="${IMG.qrweb}" alt="QR to dashboard" class="rpt-qr-img"></div>
        <div class="rpt-qr-card-caption">eduaakashaa.in/tnea-2026</div>
      </div>
      <div class="rpt-qr-card rpt-qr-card-wa">
        <div class="rpt-qr-card-label">💬 Join EduAakashaa TNEA group</div>
        <div class="rpt-qr-img-wrap"><img src="${IMG.qrwa}" alt="QR to WhatsApp TNEA group" class="rpt-qr-img"></div>
        <div class="rpt-qr-card-caption">Real-time TNEA 2026 updates</div>
      </div>
    </div>
  </div>

  <footer class="rpt-footer" id="sec-contact">
    <div class="rpt-footer-block">
      <strong>Reach Us</strong>
      <a href="tel:+918015722706">+91 80157 22706 (India)</a>
      <a href="mailto:info@eduaakashaa.com">info@eduaakashaa.com</a>
      <a href="https://www.eduaakashaa.in">www.eduaakashaa.in</a>
    </div>
    <div class="rpt-footer-block">
      <strong>Hours</strong>
      <span>Mon – Fri · 9:00 – 22:00</span>
      <span>Saturday · 9:00 – 16:00</span>
      <span>Sunday · 9:00 – 16:00</span>
      <span>Coimbatore, TN</span>
    </div>
    <div class="rpt-footer-block">
      <strong>Stay Connected</strong>
      <a href="https://wa.me/918015722706">💬 WhatsApp Channel</a>
      <a href="https://www.instagram.com/eduaakashaa">📷 Instagram @eduaakashaa</a>
      <a href="https://www.linkedin.com/company/eduaakashaa">💼 LinkedIn</a>
      <a href="https://www.youtube.com/@eduaakashaa">▶️ YouTube</a>
    </div>
  </footer>
  <div class="rpt-final">© ${new Date().getFullYear()} EduAakashaa · Generated ${date} · This is an AI-generated report — verify with tneaonline.org before final action</div>
</div>
</body>
</html>`;

  // Open in new window
  const w = window.open('', '_blank');
  if(!w){
    alert('Please allow popups for this site to generate the PDF report.');
    return;
  }
  w.document.write(html);
  w.document.close();
}

