// === EXCEL REPORT GENERATOR ===
function generateExcelReport(){
  if(typeof XLSX === 'undefined'){
    alert('Excel library hasn\'t loaded yet.\n\nThis page uses SheetJS from a CDN to generate Excel files. If you\'re seeing this message:\n\n1. Wait 5 seconds and try again (slow connection)\n2. Check your internet — the CDN at cdn.jsdelivr.net needs to be reachable\n3. If you\'re on an offline / restricted network, use the Markdown / CSV download option instead\n\nIn the meantime, you can still use Generate PDF Report — it works fully offline.');
    return;
  }
  const ci = COMM_IDX[DASH.community];
  const date = new Date().toLocaleDateString('en-GB', { day:'numeric', month:'long', year:'numeric' });
  const dateISO = new Date().toISOString().split('T')[0];

  // Helpers
  const naacOf = (idx) => NAAC_GRADES[idx] || '';
  const nirfOf = (idx) => { const n = NIRF_RANKS[idx]; return n ? '#' + n.display : ''; };
  const eaOf   = (idx) => { const e = EA_RANK[idx]; return (e && e < 999) ? e : ''; };

  // === Sheet 1: Cover & Profile ===
  const cover = [
    ['EduAakashaa — TNEA 2026 Personalised Report'],
    ['Guiding students towards the right future'],
    [''],
    ['Generated', date],
    ['Maths', DASH.marks.m, 'Physics', DASH.marks.p, 'Chemistry', DASH.marks.c],
    ['TNEA Cutoff', DASH.cutoff, 'Community', COMM_LABEL[DASH.community]],
    [''],
    ['─── About this report ───'],
    ['This Excel workbook contains all the data shown in your dashboard, organised across 5 sheets.'],
    ['Numbers are computed from the official TNEA 2025 cutoff dataset (cutoff.tneaonline.org).'],
    ['Recommendations are produced algorithmically — always validate with tneaonline.org and a counsellor.'],
    [''],
    ['─── EduAakashaa Contact ───'],
    ['India',     '+91 80157 22706'],
    ['Email',     'info@eduaakashaa.com'],
    ['Website',   'www.eduaakashaa.in'],
    ['WhatsApp',  'https://wa.me/918015722706'],
    ['Hours',     'Mon–Fri 9:00–22:00 · Sat & Sun 9:00–16:00'],
    ['Locations', 'Coimbatore, Tamil Nadu'],
    [''],
    ['📞 Book a free 30-minute counselling call — we will review this report with you.'],
  ];

  // === Sheet 2: Top picks (Dream / Reach / Safe) ===
  // Reuse the same algorithm as renderTierPicks
  const allCands = TNEA_DATA.records
    .filter(r => r[ci] != null && (DASH.cutoff - r[ci]) >= -5 && passesFilters(r))
    .map(r => ({
      r, college: TNEA_DATA.colleges[r[0]], branch: TNEA_DATA.branches[r[1]],
      cutoff: r[ci], headroom: DASH.cutoff - r[ci], ea: EA_RANK[r[0]] || 999,
    }));
  const dedupSort = (arr) => {
    const seen = new Map();
    for(const c of arr){ if(!seen.has(c.r[0]) || c.ea < seen.get(c.r[0]).ea) seen.set(c.r[0], c); }
    return Array.from(seen.values()).sort((a,b)=> a.ea - b.ea);
  };
  const dreamRaw = dedupSort(allCands.filter(c => c.headroom >= -5 && c.headroom < 3));
  const reachRaw = dedupSort(allCands.filter(c => c.headroom >= 3  && c.headroom < 8));
  const safeRaw  = dedupSort(allCands.filter(c => c.headroom >= 8));
  const dream = dreamRaw.slice(0,10);
  const usedDream = new Set(dream.map(c => c.r[0]));
  const reach = reachRaw.filter(c => !usedDream.has(c.r[0])).slice(0,10);
  const usedReach = new Set([...usedDream, ...reach.map(c => c.r[0])]);
  const safe = safeRaw.filter(c => !usedReach.has(c.r[0])).slice(0,10);

  const buildPickRow = (c, tier) => [
    tier, c.ea < 999 ? c.ea : '', c.college.n, c.college.d, c.college.t,
    c.branch.c, c.branch.n, nirfOf(c.r[0]), naacOf(c.r[0]),
    c.cutoff, c.headroom.toFixed(1)
  ];
  const picks = [
    ['Tier','EA Rank','College','District','Type','Branch Code','Branch Name','NIRF 2024','NAAC','2025 Cutoff','Headroom']
  ];
  dream.forEach(c => picks.push(buildPickRow(c, 'DREAM')));
  reach.forEach(c => picks.push(buildPickRow(c, 'REACH')));
  safe.forEach( c => picks.push(buildPickRow(c, 'SAFE')));

  // === Sheet 3: Full predictor (all reachable, sorted by cutoff desc) ===
  const allReach = TNEA_DATA.records
    .filter(r => r[ci] != null && r[ci] <= DASH.cutoff + 2 && passesFilters(r))
    .sort((a,b) => b[ci] - a[ci]);
  const predictor = [
    ['#','EA Rank','College','District','Type','Branch Code','Branch Name','NIRF 2024','NAAC','2025 Cutoff','Buffer']
  ];
  allReach.forEach((r, i) => {
    const c = TNEA_DATA.colleges[r[0]];
    const b = TNEA_DATA.branches[r[1]];
    predictor.push([
      i+1, eaOf(r[0]), c.n, c.d, c.t, b.c, b.n,
      nirfOf(r[0]), naacOf(r[0]), r[ci], (DASH.cutoff - r[ci]).toFixed(1)
    ]);
  });

  // === Sheet 4: Branch trade-off (best ranked college per branch) ===
  const { rankByCollege, totalRanked } = computeCollegeRanks();
  const RANK_BRANCHES = ['CS','AM','AD','IT','EC','SC','EE','CE','ME','BM','CH','MZ','AE','BT','RM','AG'];
  const tradeoff = [
    ['Branch Code','Branch Name','Best Achievable College Rank','College Name','District','Type','EA Rank','NIRF','NAAC','2025 Cutoff','Buffer']
  ];
  for(const bcode of RANK_BRANCHES){
    const bIdx = bIdxByCode(bcode);
    if(bIdx < 0) continue;
    const reachableForBranch = TNEA_DATA.records.filter(r =>
      r[1] === bIdx && r[ci] != null && r[ci] <= DASH.cutoff + 2
    );
    if(reachableForBranch.length === 0){
      tradeoff.push([bcode, bNameByCode(bcode), '— not reachable —', '', '', '', '', '', '', '', '']);
      continue;
    }
    let best = null, bestRank = Infinity;
    for(const r of reachableForBranch){
      const rk = rankByCollege[r[0]];
      if(rk != null && rk < bestRank){ bestRank = rk; best = r; }
    }
    if(best){
      const c = TNEA_DATA.colleges[best[0]];
      tradeoff.push([
        bcode, bNameByCode(bcode), `#${bestRank} of ${totalRanked}`,
        c.n, c.d, c.t, eaOf(best[0]), nirfOf(best[0]), naacOf(best[0]),
        best[ci], (DASH.cutoff - best[ci]).toFixed(1)
      ]);
    }
  }

  // === Sheet 5: Top 30 colleges in your community by cutoff ===
  const collegeBest = {};
  for(const r of TNEA_DATA.records){
    if(r[ci] == null) continue;
    if(!collegeBest[r[0]] || r[ci] > collegeBest[r[0]].cutoff){
      collegeBest[r[0]] = { idx: r[0], cutoff: r[ci], record: r };
    }
  }
  const top30 = Object.values(collegeBest)
    .sort((a,b)=> b.cutoff - a.cutoff)
    .slice(0, 30);
  const top30Sheet = [
    ['Rank in Community','EA Rank','College','District','Type','Highest Cutoff (any branch)','In Reach?','NIRF','NAAC']
  ];
  top30.forEach((x, i) => {
    const c = TNEA_DATA.colleges[x.idx];
    top30Sheet.push([
      i+1, eaOf(x.idx), c.n, c.d, c.t, x.cutoff,
      x.cutoff <= DASH.cutoff ? 'YES' : 'no',
      nirfOf(x.idx), naacOf(x.idx)
    ]);
  });

  // Build workbook
  const wb = XLSX.utils.book_new();
  const wsCover     = XLSX.utils.aoa_to_sheet(cover);
  const wsPicks     = XLSX.utils.aoa_to_sheet(picks);
  const wsPredictor = XLSX.utils.aoa_to_sheet(predictor);
  const wsTradeoff  = XLSX.utils.aoa_to_sheet(tradeoff);
  const wsTop30     = XLSX.utils.aoa_to_sheet(top30Sheet);

  // Set column widths for readability
  wsCover['!cols']     = [{wch:18},{wch:42},{wch:18},{wch:12},{wch:18},{wch:12}];
  wsPicks['!cols']     = [{wch:8},{wch:9},{wch:55},{wch:16},{wch:18},{wch:6},{wch:34},{wch:11},{wch:7},{wch:11},{wch:10}];
  wsPredictor['!cols'] = [{wch:5},{wch:9},{wch:55},{wch:16},{wch:18},{wch:6},{wch:34},{wch:11},{wch:7},{wch:11},{wch:9}];
  wsTradeoff['!cols']  = [{wch:6},{wch:34},{wch:24},{wch:50},{wch:14},{wch:18},{wch:9},{wch:11},{wch:7},{wch:11},{wch:9}];
  wsTop30['!cols']     = [{wch:6},{wch:9},{wch:55},{wch:16},{wch:18},{wch:14},{wch:10},{wch:11},{wch:7}];

  XLSX.utils.book_append_sheet(wb, wsCover,     'Cover & Contact');
  XLSX.utils.book_append_sheet(wb, wsPicks,     'Top Picks');
  XLSX.utils.book_append_sheet(wb, wsPredictor, 'Full Predictor');
  XLSX.utils.book_append_sheet(wb, wsTradeoff,  'Branch Trade-off');
  XLSX.utils.book_append_sheet(wb, wsTop30,     'Top 30 by Cutoff');

  const filename = `EduAakashaa_TNEA2026_Report_${dateISO}.xlsx`;
  XLSX.writeFile(wb, filename);
}
document.getElementById('rptXLSX')?.addEventListener('click', generateExcelReport);

