// SHARE BUTTONS
const pageUrl = window.location.href;
const shareMessage = `Just found a solid TNEA 2026 admission guide from EduAakashaa — covers the full 10-step process, document checklist, reservation, common mistakes and FAQ. Saves a lot of confusion if you're applying this year.`;
const shareTitle = `TNEA 2026 Admission Guide · EduAakashaa`;

// WhatsApp share
document.getElementById('shareWA').addEventListener('click',()=>{
  const text = encodeURIComponent(`${shareMessage}\n\n${pageUrl}`);
  window.open(`https://wa.me/?text=${text}`, '_blank','noopener');
});

// Email share
document.getElementById('shareEmail').addEventListener('click',()=>{
  const subject = encodeURIComponent(shareTitle);
  const body = encodeURIComponent(`${shareMessage}\n\n${pageUrl}\n\n— Shared from EduAakashaa`);
  window.location.href = `mailto:?subject=${subject}&body=${body}`;
});

// Copy link
document.getElementById('shareCopy').addEventListener('click',async ()=>{
  const btn = document.getElementById('shareCopy');
  const txt = document.getElementById('copyText');
  try{
    if(navigator.share){
      // On mobile: offer native share sheet as bonus
      try{
        await navigator.share({title: shareTitle, text: shareMessage, url: pageUrl});
        return;
      }catch(e){/* fall through to copy */}
    }
    await navigator.clipboard.writeText(pageUrl);
    btn.classList.add('copied');
    txt.textContent = 'Link copied!';
    setTimeout(()=>{
      btn.classList.remove('copied');
      txt.textContent = 'Copy link';
    }, 2200);
  }catch(err){
    // Fallback: create temp textarea
    const ta = document.createElement('textarea');
    ta.value = pageUrl; document.body.appendChild(ta); ta.select();
    try{ document.execCommand('copy'); }catch(e){}
    document.body.removeChild(ta);
    btn.classList.add('copied');
    txt.textContent = 'Link copied!';
    setTimeout(()=>{ btn.classList.remove('copied'); txt.textContent='Copy link'; }, 2200);
  }
});

// Hydrate inline base64 images into <img data-img="key"> placeholders
document.querySelectorAll('img[data-img]').forEach(function(el){
  var k = el.dataset.img;
  if (window.IMG && window.IMG[k]) el.src = window.IMG[k];
});
